#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#include "../common.h"
#include "../util/timer/timer.h"
#include "./kernel_cpu.h"

void 
kernel_cpu(	int cores_arg,

			record *records,
			knode *knodes,
			long knodes_elem,

			int order,
			long maxheight,
			int count,

			long *currKnode,
			long *offset,
			int *keys,
			record *ans)
{
	// timer
	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	time0 = get_time();

	omp_set_num_threads(cores_arg);

	#pragma omp parallel for
	for(int i = 0; i < count; i++){
		// process levels of the tree
		for(int j = 0; j < maxheight; j++){

			if((knodes[currKnode[i]].keys[j] <= keys[i]) && (knodes[currKnode[i]].keys[j+1] > keys[i])){
				if(knodes[currKnode[i]].indices[j] < knodes_elem){
					offset[i] = knodes[currKnode[i]].indices[j];
				}
			}

			// set for next tree level
			currKnode[i] = offset[i];
		}

		// At this point, we have a candidate leaf node which may contain
		// the target record.  Check each key to hopefully find the record
		if(knodes[currKnode[i]].keys[0] == keys[i]){
			ans[i].value = records[knodes[currKnode[i]].indices[0]].value;
		}
	}

	time6 = get_time();

	// Display timing
	printf("Time spent in different stages of CPU KERNEL:\n");
	printf("%15.12f s, %15.12f %% : CPU: PROCESSING\n", (float) (time6-time0) / 1000000, (float) (time6-time0) / (float) (time6-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", (float) (time6-time0) / 1000000);
}

