void kernel_cpu(int cores_arg, record *records, knode *knodes, long knodes_elem, int order, long maxheight, int count, long *currKnode, long *offset, int *keys, record *ans) {
    // Set the number of threads
    omp_set_num_threads(cores_arg);

    #pragma omp parallel for
    for (int i = 0; i < count; i++) {
        // Process levels of the tree
        for (int j = 0; j < maxheight; j++) {
            if ((knodes[currKnode[i]].keys[j] <= keys[i]) && (knodes[currKnode[i]].keys[j + 1] > keys[i])) {
                if (knodes[offset[i]].indices[j] < knodes_elem) {
                    offset[i] = knodes[offset[i]].indices[j];
                }
            }
        }

        // At this point, we have a candidate leaf node which may contain
        // the target record.  Check each key to hopefully find the record
        if (knodes[currKnode[i]].keys[0] == keys[i]) { // Changed j to 0
            ans[i].value = records[knodes[currKnode[i]].indices[0]].value; // Changed j to 0
        }
    }
}

