#include <iostream>
#include <fstream>
#include <omp.h>

// Constants
const float GAMMA = 1.4f;
const int iterations = 2000;
const int block_length = 192;
const int NDIM = 3;
const int NNB = 4;
const int RK = 3;  // 3rd order RK
const float ff_mach = 1.2f;
const float deg_angle_of_attack = 0.0f;

// Variables
const int VAR_DENSITY = 0;
const int VAR_MOMENTUM = 1;
const int VAR_DENSITY_ENERGY = (VAR_MOMENTUM + NDIM);
const int NVAR = (VAR_DENSITY_ENERGY + 1);

// Function to compute flux contribution
void compute_flux_contribution(float& density, float momentum[3], float& density_energy, float& pressure, float velocity[3], float fc_momentum_x[3], float fc_momentum_y[3], float fc_momentum_z[3], float fc_density_energy[3]) {
    fc_momentum_x[0] = velocity[0] * momentum[0] + pressure;
    fc_momentum_x[1] = velocity[0] * momentum[1];
    fc_momentum_x[2] = velocity[0] * momentum[2];

    fc_momentum_y[0] = fc_momentum_x[1];
    fc_momentum_y[1] = velocity[1] * momentum[1] + pressure;
    fc_momentum_y[2] = velocity[1] * momentum[2];

    fc_momentum_z[0] = fc_momentum_x[2];
    fc_momentum_z[1] = fc_momentum_y[2];
    fc_momentum_z[2] = velocity[2] * momentum[2] + pressure;

    float de_p = density_energy + pressure;
    fc_density_energy[0] = velocity[0] * de_p;
    fc_density_energy[1] = velocity[1] * de_p;
    fc_density_energy[2] = velocity[2] * de_p;
}

// Function to compute velocity
void compute_velocity(float& density, float momentum[3], float velocity[3]) {
    velocity[0] = momentum[0] / density;
    velocity[1] = momentum[1] / density;
    velocity[2] = momentum[2] / density;
}

// Function to compute speed squared
float compute_speed_sqd(float velocity[3]) {
    return velocity[0] * velocity[0] + velocity[1] * velocity[1] + velocity[2] * velocity[2];
}

// Function to compute pressure
float compute_pressure(float& density, float& density_energy, float& speed_sqd) {
    return (GAMMA - 1.0f) * (density_energy - 0.5f * density * speed_sqd);
}

// Function to compute speed of sound
float compute_speed_of_sound(float& density, float& pressure) {
    return sqrtf(GAMMA * pressure / density);
}

// Function to initialize variables
void initialize_variables(float* variables, int nelr) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        variables[i + VAR_DENSITY * nelr] = 1.4f;
        variables[i + (VAR_MOMENTUM + 0) * nelr] = 0.0f;
        variables[i + (VAR_MOMENTUM + 1) * nelr] = 0.0f;
        variables[i + (VAR_MOMENTUM + 2) * nelr] = 0.0f;
        variables[i + VAR_DENSITY_ENERGY * nelr] = 1.0f;
    }
}

// Function to compute step factor
void compute_step_factor(float* variables, float* areas, float* step_factors, int nelr) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        float density = variables[i + VAR_DENSITY * nelr];
        float momentum[3] = {variables[i + (VAR_MOMENTUM + 0) * nelr], variables[i + (VAR_MOMENTUM + 1) * nelr], variables[i + (VAR_MOMENTUM + 2) * nelr]};
        float density_energy = variables[i + VAR_DENSITY_ENERGY * nelr];

        float velocity[3];
        compute_velocity(density, momentum, velocity);
        float speed_sqd = compute_speed_sqd(velocity);
        float pressure = compute_pressure(density, density_energy, speed_sqd);
        float speed_of_sound = compute_speed_of_sound(density, pressure);

        step_factors[i] = 0.5f / (sqrtf(areas[i]) * (sqrtf(speed_sqd) + speed_of_sound));
    }
}

// Function to compute flux
void compute_flux(float* variables, int* elements_surrounding_elements, float* normals, float* fluxes, int nelr) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        float density_i = variables[i + VAR_DENSITY * nelr];
        float momentum_i[3] = {variables[i + (VAR_MOMENTUM + 0) * nelr], variables[i + (VAR_MOMENTUM + 1) * nelr], variables[i + (VAR_MOMENTUM + 2) * nelr]};
        float density_energy_i = variables[i + VAR_DENSITY_ENERGY * nelr];

        float velocity_i[3];
        compute_velocity(density_i, momentum_i, velocity_i);
        float speed_sqd_i = compute_speed_sqd(velocity_i);
        float speed_i = sqrtf(speed_sqd_i);
        float pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
        float speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);

        float fc_i_momentum_x[3], fc_i_momentum_y[3], fc_i_momentum_z[3];
        float fc_i_density_energy[3];
        compute_flux_contribution(density_i, momentum_i, density_energy_i, pressure_i, velocity_i, fc_i_momentum_x, fc_i_momentum_y, fc_i_momentum_z, fc_i_density_energy);

        float flux_i_density = 0.0f;
        float flux_i_momentum[3] = {0.0f, 0.0f, 0.0f};
        float flux_i_density_energy = 0.0f;

        for (int j = 0; j < NNB; j++) {
            int nb = elements_surrounding_elements[i + j * nelr];
            float normal[3] = {normals[i + (j + 0 * NNB) * nelr], normals[i + (j + 1 * NNB) * nelr], normals[i + (j + 2 * NNB) * nelr]};
            float normal_len = sqrtf(normal[0] * normal[0] + normal[1] * normal[1] + normal[2] * normal[2]);

            if (nb >= 0) {
                float density_nb = variables[nb + VAR_DENSITY * nelr];
                float momentum_nb[3] = {variables[nb + (VAR_MOMENTUM + 0) * nelr], variables[nb + (VAR_MOMENTUM + 1) * nelr], variables[nb + (VAR_MOMENTUM + 2) * nelr]};
                float density_energy_nb = variables[nb + VAR_DENSITY_ENERGY * nelr];

                float velocity_nb[3];
                compute_velocity(density_nb, momentum_nb, velocity_nb);
                float speed_sqd_nb = compute_speed_sqd(velocity_nb);
                float pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
                float speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);

                float fc_nb_momentum_x[3], fc_nb_momentum_y[3], fc_nb_momentum_z[3];
                float fc_nb_density_energy[3];
                compute_flux_contribution(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb, fc_nb_momentum_x, fc_nb_momentum_y, fc_nb_momentum_z, fc_nb_density_energy);

                float factor = -normal_len * 0.2f * 0.5f * (speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                flux_i_density += factor * (density_i - density_nb);
                flux_i_density_energy += factor * (density_energy_i - density_energy_nb);
                flux_i_momentum[0] += factor * (momentum_i[0] - momentum_nb[0]);
                flux_i_momentum[1] += factor * (momentum_i[1] - momentum_nb[1]);
                flux_i_momentum[2] += factor * (momentum_i[2] - momentum_nb[2]);

                factor = 0.5f * normal[0];
                flux_i_density += factor * (momentum_nb[0] + momentum_i[0]);
                flux_i_density_energy += factor * (fc_nb_density_energy[0] + fc_i_density_energy[0]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[0] + fc_i_momentum_x[0]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[0] + fc_i_momentum_y[0]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[0] + fc_i_momentum_z[0]);

                factor = 0.5f * normal[1];
                flux_i_density += factor * (momentum_nb[1] + momentum_i[1]);
                flux_i_density_energy += factor * (fc_nb_density_energy[1] + fc_i_density_energy[1]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[1] + fc_i_momentum_x[1]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[1] + fc_i_momentum_y[1]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[1] + fc_i_momentum_z[1]);

                factor = 0.5f * normal[2];
                flux_i_density += factor * (momentum_nb[2] + momentum_i[2]);
                flux_i_density_energy += factor * (fc_nb_density_energy[2] + fc_i_density_energy[2]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[2] + fc_i_momentum_x[2]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[2] + fc_i_momentum_y[2]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[2] + fc_i_momentum_z[2]);
            } else if (nb == -1) {
                flux_i_momentum[0] += normal[0] * pressure_i;
                flux_i_momentum[1] += normal[1] * pressure_i;
                flux_i_momentum[2] += normal[2] * pressure_i;
            } else if (nb == -2) {
                float factor = 0.5f * normal[0];
                flux_i_density += factor * (0.0f + momentum_i[0]);
                flux_i_density_energy += factor * (0.0f + fc_i_density_energy[0]);
                flux_i_momentum[0] += factor * (0.0f + fc_i_momentum_x[0]);
                flux_i_momentum[1] += factor * (0.0f + fc_i_momentum_y[0]);
                flux_i_momentum[2] += factor * (0.0f + fc_i_momentum_z[0]);

                factor = 0.5f * normal[1];
                flux_i_density += factor * (0.0f + momentum_i[1]);
                flux_i_density_energy += factor * (0.0f + fc_i_density_energy[1]);
                flux_i_momentum[0] += factor * (0.0f + fc_i_momentum_x[1]);
                flux_i_momentum[1] += factor * (0.0f + fc_i_momentum_y[1]);
                flux_i_momentum[2] += factor * (0.0f + fc_i_momentum_z[1]);

                factor = 0.5f * normal[2];
                flux_i_density += factor * (0.0f + momentum_i[2]);
                flux_i_density_energy += factor * (0.0f + fc_i_density_energy[2]);
                flux_i_momentum[0] += factor * (0.0f + fc_i_momentum_x[2]);
                flux_i_momentum[1] += factor * (0.0f + fc_i_momentum_y[2]);
                flux_i_momentum[2] += factor * (0.0f + fc_i_momentum_z[2]);
            }
        }

        fluxes[i + VAR_DENSITY * nelr] = flux_i_density;
        fluxes[i + (VAR_MOMENTUM + 0) * nelr] = flux_i_momentum[0];
        fluxes[i + (VAR_MOMENTUM + 1) * nelr] = flux_i_momentum[1];
        fluxes[i + (VAR_MOMENTUM + 2) * nelr] = flux_i_momentum[2];
        fluxes[i + VAR_DENSITY_ENERGY * nelr] = flux_i_density_energy;
    }
}

// Function to time step
void time_step(float* old_variables, float* variables, float* step_factors, float* fluxes, int nelr, int j) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        float factor = step_factors[i] / float(RK + 1 - j);

        variables[i + VAR_DENSITY * nelr] = old_variables[i + VAR_DENSITY * nelr] + factor * fluxes[i + VAR_DENSITY * nelr];
        variables[i + VAR_DENSITY_ENERGY * nelr] = old_variables[i + VAR_DENSITY_ENERGY * nelr] + factor * fluxes[i + VAR_DENSITY_ENERGY * nelr];
        variables[i + (VAR_MOMENTUM + 0) * nelr] = old_variables[i + (VAR_MOMENTUM + 0) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 0) * nelr];
        variables[i + (VAR_MOMENTUM + 1) * nelr] = old_variables[i + (VAR_MOMENTUM + 1) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 1) * nelr];
        variables[i + (VAR_MOMENTUM + 2) * nelr] = old_variables[i + (VAR_MOMENTUM + 2) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 2) * nelr];
    }
}

int main(int argc, char** argv) {
    if (argc < 2) {
        std::cout << "Specify data file name" << std::endl;
        return 0;
    }
    const char* data_file_name = argv[1];

    int nel;
    int nelr;

    // Read in domain geometry
    float* areas;
    int* elements_surrounding_elements;
    float* normals;
    {
        std::ifstream file(data_file_name);

        file >> nel;
        nelr = block_length * ((nel / block_length) + std::min(1, nel % block_length));

        float* h_areas = new float[nelr];
        int* h_elements_surrounding_elements = new int[nelr * NNB];
        float* h_normals = new float[nelr * NDIM * NNB];

        // Read in data
        for (int i = 0; i < nel; i++) {
            file >> h_areas[i];
            for (int j = 0; j < NNB; j++) {
                file >> h_elements_surrounding_elements[i + j * nelr];
                if (h_elements_surrounding_elements[i + j * nelr] < 0) h_elements_surrounding_elements[i + j * nelr] = -1;
                h_elements_surrounding_elements[i + j * nelr]--; // it's coming in with Fortran numbering

                for (int k = 0; k < NDIM; k++) {
                    file >> h_normals[i + (j + k * NNB) * nelr];
                    h_normals[i + (j + k * NNB) * nelr] = -h_normals[i + (j + k * NNB) * nelr];
                }
            }
        }

        // Fill in remaining data
        int last = nel - 1;
        for (int i = nel; i < nelr; i++) {
            h_areas[i] = h_areas[last];
            for (int j = 0; j < NNB; j++) {
                // Duplicate the last element
                h_elements_surrounding_elements[i + j * nelr] = h_elements_surrounding_elements[last + j * nelr];
                for (int k = 0; k < NDIM; k++) h_normals[last + (j + k * NNB) * nelr] = h_normals[last + (j + k * NNB) * nelr];
            }
        }

        areas = new float[nelr];
        for (int i = 0; i < nelr; i++) areas[i] = h_areas[i];

        elements_surrounding_elements = new int[nelr * NNB];
        for (int i = 0; i < nelr * NNB; i++) elements_surrounding_elements[i] = h_elements_surrounding_elements[i];

        normals = new float[nelr * NDIM * NNB];
        for (int i = 0; i < nelr * NDIM * NNB; i++) normals[i] = h_normals[i];

        delete[] h_areas;
        delete[] h_elements_surrounding_elements;
        delete[] h_normals;
    }

    // Create arrays and set initial conditions
    float* variables = new float[nelr * NVAR];
    initialize_variables(variables, nelr);

    float* old_variables = new float[nelr * NVAR];
    for (int i = 0; i < nelr * NVAR; i++) old_variables[i] = variables[i];

    float* fluxes = new float[nelr * NVAR];
    for (int i = 0; i < nelr * NVAR; i++) fluxes[i] = 0.0f;

    float* step_factors = new float[nelr];
    for (int i = 0; i < nelr; i++) step_factors[i] = 0.0f;

    // Make sure all memory is allocated before we start timing
    for (int i = 0; i < nelr * NVAR; i++) old_variables[i] = variables[i];
    for (int i = 0; i < nelr * NVAR; i++) fluxes[i] = 0.0f;
    for (int i = 0; i < nelr; i++) step_factors[i] = 0.0f;

    // Start timing
    double start_time = omp_get_wtime();

    // Begin iterations
    for (int i = 0; i < iterations; i++) {
        // Copy old variables
        for (int j = 0; j < nelr * NVAR; j++) old_variables[j] = variables[j];

        // Compute step factor
        compute_step_factor(variables, areas, step_factors, nelr);

        for (int j = 0; j < RK; j++) {
            // Compute flux
            compute_flux(variables, elements_surrounding_elements, normals, fluxes, nelr);

            // Time step
            time_step(old_variables, variables, step_factors, fluxes, nelr, j);
        }
    }

    // Stop timing
    double end_time = omp_get_wtime();

    // Print time
    std::cout << "Time: " << (end_time - start_time) / iterations << " seconds per iteration" << std::endl;

    // Save solution
    std::ofstream file("density");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) file << variables[i + VAR_DENSITY * nelr] << std::endl;

    file.close();

    file.open("momentum");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) {
        for (int j = 0; j < NDIM; j++) file << variables[i + (VAR_MOMENTUM + j) * nelr] << " ";
        file << std::endl;
    }

    file.close();

    file.open("density_energy");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) file << variables[i + VAR_DENSITY_ENERGY * nelr] << std::endl;

    file.close();

    // Clean up
    delete[] areas;
    delete[] elements_surrounding_elements;
    delete[] normals;
    delete[] variables;
    delete[] old_variables;
    delete[] fluxes;
    delete[] step_factors;

    return 0;
}

#include <iostream>
#include <fstream>
#include <omp.h>

#define GAMMA 1.4f
#define iterations 2000
#define block_length 192

#define NDIM 3
#define NNB 4

#define RK 3	// 3rd order RK
#define ff_mach 1.2f
#define deg_angle_of_attack 0.0f

#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)

void compute_flux_contribution(float& density, float3& momentum, float& density_energy, float& pressure, float3& velocity, float3& fc_momentum_x, float3& fc_momentum_y, float3& fc_momentum_z, float3& fc_density_energy)
{
	fc_momentum_x.x = velocity.x*momentum.x + pressure;
	fc_momentum_x.y = velocity.x*momentum.y;
	fc_momentum_x.z = velocity.x*momentum.z;


	fc_momentum_y.x = fc_momentum_x.y;
	fc_momentum_y.y = velocity.y*momentum.y + pressure;
	fc_momentum_y.z = velocity.y*momentum.z;

	fc_momentum_z.x = fc_momentum_x.z;
	fc_momentum_z.y = fc_momentum_y.z;
	fc_momentum_z.z = velocity.z*momentum.z + pressure;

	float de_p = density_energy+pressure;
	fc_density_energy.x = velocity.x*de_p;
	fc_density_energy.y = velocity.y*de_p;
	fc_density_energy.z = velocity.z*de_p;
}

void compute_velocity(float& density, float3& momentum, float3& velocity)
{
	velocity.x = momentum.x / density;
	velocity.y = momentum.y / density;
	velocity.z = momentum.z / density;
}

float compute_speed_sqd(float3& velocity)
{
	return velocity.x*velocity.x + velocity.y*velocity.y + velocity.z*velocity.z;
}

float compute_pressure(float& density, float& density_energy, float& speed_sqd)
{
	return (GAMMA-1.0f)*(density_energy - 0.5f*density*speed_sqd);
}

float compute_speed_of_sound(float& density, float& pressure)
{
	return sqrtf(GAMMA*pressure/density);
}

void dump(float* variables, int nel, int nelr)
{
	std::ofstream file("density");
	file << nel << " " << nelr << std::endl;
	for(int i = 0; i < nel; i++) file << variables[i + VAR_DENSITY*nelr] << std::endl;

	file.close();

	file.open("momentum");
	file << nel << " " << nelr << std::endl;
	for(int i = 0; i < nel; i++)
	{
		for(int j = 0; j != NDIM; j++)
			file << variables[i + (VAR_MOMENTUM+j)*nelr] << " ";
		file << std::endl;
	}

	file.close();

	file.open("density_energy");
	file << nel << " " << nelr << std::endl;
	for(int i = 0; i < nel; i++) file << variables[i + VAR_DENSITY_ENERGY*nelr] << std::endl;
}

int main(int argc, char** argv)
{
	if (argc < 2)
	{
		std::cout << "specify data file name" << std::endl;
		return 0;
	}
	const char* data_file_name = argv[1];

	int nel;
	int nelr;

	// read in domain geometry
	float* areas;
	int* elements_surrounding_elements;
	float* normals;
	{
		std::ifstream file(data_file_name);

		file >> nel;
		nelr = ((nel / block_length )+ std::min(1, nel % block_length))*block_length;

		areas = new float[nelr];
		int* h_elements_surrounding_elements = new int[nelr*NNB];
		float* h_normals = new float[nelr*NDIM*NNB];


		// read in data
		for(int i = 0; i < nel; i++)
		{
			file >> areas[i];
			for(int j = 0; j < NNB; j++)
			{
				file >> h_elements_surrounding_elements[i + j*nelr];
				if(h_elements_surrounding_elements[i+j*nelr] < 0) h_elements_surrounding_elements[i+j*nelr] = -1;
				h_elements_surrounding_elements[i + j*nelr]--; //it's coming in with Fortran numbering				

				for(int k = 0; k < NDIM; k++)
				{
					file >> h_normals[i + (j + k*NNB)*nelr];
					h_normals[i + (j + k*NNB)*nelr] = -h_normals[i + (j + k*NNB)*nelr];
				}
			}
		}

		// fill in remaining data
		int last = nel-1;
		for(int i = nel; i < nelr; i++)
		{
			areas[i] = areas[last];
			for(int j = 0; j < NNB; j++)
			{
				// duplicate the last element
				h_elements_surrounding_elements[i + j*nelr] = h_elements_surrounding_elements[last + j*nelr];	
				for(int k = 0; k < NDIM; k++) h_normals[last + (j + k*NNB)*nelr] = h_normals[last + (j + k*NNB)*nelr];
			}
		}

		elements_surrounding_elements = new int[nelr*NNB];
		for(int i = 0; i < nelr*NNB; i++) elements_surrounding_elements[i] = h_elements_surrounding_elements[i];

		normals = new float[nelr*NDIM*NNB];
		for(int i = 0; i < nelr*NDIM*NNB; i++) normals[i] = h_normals[i];

		delete[] h_elements_surrounding_elements;
		delete[] h_normals;
	}

	// Create arrays and set initial conditions
	float* variables = new float[nelr*NVAR];
	float* old_variables = new float[nelr*NVAR];   	
	float* fluxes = new float[nelr*NVAR];
	float* step_factors = new float[nelr]; 

	// set far field conditions 
	float ff_variable[NVAR];
	const float angle_of_attack = 3.1415926535897931 / 180.0f * deg_angle_of_attack;

	ff_variable[VAR_DENSITY] = 1.4;

	float ff_pressure = 1.0f;
	float ff_speed_of_sound = sqrt(GAMMA*ff_pressure / ff_variable[VAR_DENSITY]);
	float ff_speed = ff_mach*ff_speed_of_sound;

	float3 ff_velocity;
	ff_velocity.x = ff_speed*cos(angle_of_attack);
	ff_velocity.y = ff_speed*sin(angle_of_attack);
	ff_velocity.z = 0.0f;

	ff_variable[VAR_MOMENTUM+0] = ff_variable[VAR_DENSITY] * ff_velocity.x;
	ff_variable[VAR_MOMENTUM+1] = ff_variable[VAR_DENSITY] * ff_velocity.y;
	ff_variable[VAR_MOMENTUM+2] = ff_variable[VAR_DENSITY] * ff_velocity.z;

	ff_variable[VAR_DENSITY_ENERGY] = ff_variable[VAR_DENSITY]*(0.5f*(ff_speed*ff_speed)) + (ff_pressure / (GAMMA-1.0f));

	// initialize variables
	for(int i = 0; i < nelr; i++)
	{
		variables[i + VAR_DENSITY*nelr] = ff_variable[VAR_DENSITY];
		variables[i + (VAR_MOMENTUM+0)*nelr] = ff_variable[VAR_MOMENTUM+0];
		variables[i + (VAR_MOMENTUM+1)*nelr] = ff_variable[VAR_MOMENTUM+1];
		variables[i + (VAR_MOMENTUM+2)*nelr] = ff_variable[VAR_MOMENTUM+2];
		variables[i + VAR_DENSITY_ENERGY*nelr] = ff_variable[VAR_DENSITY_ENERGY];
	}

	// make sure all memory is floatly allocated before we start timing
	for(int i = 0; i < nelr*NVAR; i++) old_variables[i] = variables[i];
	for(int i = 0; i < nelr*NVAR; i++) fluxes[i] = 0.0f;
	for(int i = 0; i < nelr; i++) step_factors[i] = 0.0f;

	double start = omp_get_wtime();

	// Begin iterations
	for(int i = 0; i < iterations; i++)
	{
		for(int j = 0; j < nelr*NVAR; j++) old_variables[j] = variables[j];

		// for the first iteration we compute the time step
		#pragma omp parallel for
		for(int idx = 0; idx < nelr; idx++)
		{
			float density = variables[idx + VAR_DENSITY*nelr];
			float3 momentum;
			momentum.x = variables[idx + (VAR_MOMENTUM+0)*nelr];
			momentum.y = variables[idx + (VAR_MOMENTUM+1)*nelr];
			momentum.z = variables[idx + (VAR_MOMENTUM+2)*nelr];

			float density_energy = variables[idx + VAR_DENSITY_ENERGY*nelr];

			float3 velocity;       compute_velocity(density, momentum, velocity);
			float speed_sqd      = compute_speed_sqd(velocity);
			float pressure       = compute_pressure(density, density_energy, speed_sqd);
			float speed_of_sound = compute_speed_of_sound(density, pressure);

			// dt = float(0.5f) * sqrtf(areas[idx]) /  (||v|| + c).... but when we do time stepping, this later would need to be divided by the area, so we just do it all at once
			step_factors[idx] = 0.5f / (sqrtf(areas[idx]) * (sqrtf(speed_sqd) + speed_of_sound));
		}

		for(int j = 0; j < RK; j++)
		{
			#pragma omp parallel for
			for(int idx = 0; idx < nelr; idx++)
			{
				int j, nb;
				float3 normal; float normal_len;
				float factor;

				float density_i = variables[idx + VAR_DENSITY*nelr];
				float3 momentum_i;
				momentum_i.x = variables[idx + (VAR_MOMENTUM+0)*nelr];
				momentum_i.y = variables[idx + (VAR_MOMENTUM+1)*nelr];
				momentum_i.z = variables[idx + (VAR_MOMENTUM+2)*nelr];

				float density_energy_i = variables[idx + VAR_DENSITY_ENERGY*nelr];

				float3 velocity_i;             				compute_velocity(density_i, momentum_i, velocity_i);
				float speed_sqd_i                          = compute_speed_sqd(velocity_i);
				float speed_i                              = sqrtf(speed_sqd_i);
				float pressure_i                           = compute_pressure(density_i, density_energy_i, speed_sqd_i);
				float speed_of_sound_i                     = compute_speed_of_sound(density_i, pressure_i);
				float3 flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z;
				float3 flux_contribution_i_density_energy;	
				compute_flux_contribution(density_i, momentum_i, density_energy_i, pressure_i, velocity_i, flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z, flux_contribution_i_density_energy);

				float flux_i_density = 0.0f;
				float3 flux_i_momentum;
				flux_i_momentum.x = 0.0f;
				flux_i_momentum.y = 0.0f;
				flux_i_momentum.z = 0.0f;
				float flux_i_density_energy = 0.0f;

				float3 velocity_nb;
				float density_nb, density_energy_nb;
				float3 momentum_nb;
				float3 flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z;
				float3 flux_contribution_nb_density_energy;	
				float speed_sqd_nb, speed_of_sound_nb, pressure_nb;

				#pragma unroll
				for(j = 0; j < NNB; j++)
				{
					nb = elements_surrounding_elements[idx + j*nelr];
					normal.x = normals[idx + (j + 0*NNB)*nelr];
					normal.y = normals[idx + (j + 1*NNB)*nelr];
					normal.z = normals[idx + (j + 2*NNB)*nelr];
					normal_len = sqrtf(normal.x*normal.x + normal.y*normal.y + normal.z*normal.z);

					if(nb >= 0) 	// a legitimate neighbor
					{
						density_nb = variables[nb + VAR_DENSITY*nelr];
						momentum_nb.x = variables[nb + (VAR_MOMENTUM+0)*nelr];
						momentum_nb.y = variables[nb + (VAR_MOMENTUM+1)*nelr];
						momentum_nb.z = variables[nb + (VAR_MOMENTUM+2)*nelr];
						density_energy_nb = variables[nb + VAR_DENSITY_ENERGY*nelr];
													compute_velocity(density_nb, momentum_nb, velocity_nb);
						speed_sqd_nb                      = compute_speed_sqd(velocity_nb);
						pressure_nb                       = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
						speed_of_sound_nb                 = compute_speed_of_sound(density_nb, pressure_nb);
						compute_flux_contribution(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb, flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z, flux_contribution_nb_density_energy);

						// artificial viscosity
						factor = -normal_len*0.2f*0.5f*(speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
						flux_i_density += factor*(density_i-density_nb);
						flux_i_density_energy += factor*(density_energy_i-density_energy_nb);
						flux_i_momentum.x += factor*(momentum_i.x-momentum_nb.x);
						flux_i_momentum.y += factor*(momentum_i.y-momentum_nb.y);
						flux_i_momentum.z += factor*(momentum_i.z-momentum_nb.z);

						// accumulate cell-centered fluxes
						factor = 0.5f*normal.x;
						flux_i_density += factor*(momentum_nb.x+momentum_i.x);
						flux_i_density_energy += factor*(flux_contribution_nb_density_energy.x+flux_contribution_i_density_energy.x);
						flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.x+flux_contribution_i_momentum_x.x);
						flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.x+flux_contribution_i_momentum_y.x);
						flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.x+flux_contribution_i_momentum_z.x);

						factor = 0.5f*normal.y;
						flux_i_density += factor*(momentum_nb.y+momentum_i.y);
						flux_i_density_energy += factor*(flux_contribution_nb_density_energy.y+flux_contribution_i_density_energy.y);
						flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.y+flux_contribution_i_momentum_x.y);
						flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.y+flux_contribution_i_momentum_y.y);
						flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.y+flux_contribution_i_momentum_z.y);

						factor = 0.5f*normal.z;
						flux_i_density += factor*(momentum_nb.z+momentum_i.z);
						flux_i_density_energy += factor*(flux_contribution_nb_density_energy.z+flux_contribution_i_density_energy.z);
						flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.z+flux_contribution_i_momentum_x.z);
						flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.z+flux_contribution_i_momentum_y.z);
						flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.z+flux_contribution_i_momentum_z.z);
					}
					else if(nb == -1)	// a wing boundary
					{
						flux_i_momentum.x += normal.x*pressure_i;
						flux_i_momentum.y += normal.y*pressure_i;
						flux_i_momentum.z += normal.z*pressure_i;
					}
					else if(nb == -2) // a far field boundary
					{
						factor = 0.5f*normal.x;
						flux_i_density += factor*(ff_variable[VAR_MOMENTUM+0]+momentum_i.x);
						flux_i_density_energy += factor*(ff_variable[VAR_MOMENTUM+0]+momentum_i.x);
						flux_i_momentum.x += factor*(ff_variable[VAR_MOMENTUM+0] + momentum_i.x);
						flux_i_momentum.y += factor*(ff_variable[VAR_MOMENTUM+1] + momentum_i.y);
						flux_i_momentum.z += factor*(ff_variable[VAR_MOMENTUM+2] + momentum_i.z);

						factor = 0.5f*normal.y;
						flux_i_density += factor*(ff_variable[VAR_MOMENTUM+1]+momentum_i.y);
						flux_i_density_energy += factor*(ff_variable[VAR_MOMENTUM+1]+momentum_i.y);
						flux_i_momentum.x += factor*(ff_variable[VAR_MOMENTUM+0] + momentum_i.x);
						flux_i_momentum.y += factor*(ff_variable[VAR_MOMENTUM+1] + momentum_i.y);
						flux_i_momentum.z += factor*(ff_variable[VAR_MOMENTUM+2] + momentum_i.z);

						factor = 0.5f*normal.z;
						flux_i_density += factor*(ff_variable[VAR_MOMENTUM+2]+momentum_i.z);
						flux_i_density_energy += factor*(ff_variable[VAR_MOMENTUM+2]+momentum_i.z);
						flux_i_momentum.x += factor*(ff_variable[VAR_MOMENTUM+0] + momentum_i.x);
						flux_i_momentum.y += factor*(ff_variable[VAR_MOMENTUM+1] + momentum_i.y);
						flux_i_momentum.z += factor*(ff_variable[VAR_MOMENTUM+2] + momentum_i.z);

					}
				}

				fluxes[idx + VAR_DENSITY*nelr] = flux_i_density;
				fluxes[idx + (VAR_MOMENTUM+0)*nelr] = flux_i_momentum.x;
				fluxes[idx + (VAR_MOMENTUM+1)*nelr] = flux_i_momentum.y;
				fluxes[idx + (VAR_MOMENTUM+2)*nelr] = flux_i_momentum.z;
				fluxes[idx + VAR_DENSITY_ENERGY*nelr] = flux_i_density_energy;
			}

			#pragma omp parallel for
			for(int idx = 0; idx < nelr; idx++)
			{
				float factor = step_factors[idx]/float(RK+1-j);

				variables[idx + VAR_DENSITY*nelr] = old_variables[idx + VAR_DENSITY*nelr] + factor*fluxes[idx + VAR_DENSITY*nelr];
				variables[idx + VAR_DENSITY_ENERGY*nelr] = old_variables[idx + VAR_DENSITY_ENERGY*nelr] + factor*fluxes[idx + VAR_DENSITY_ENERGY*nelr];
				variables[idx + (VAR_MOMENTUM+0)*nelr] = old_variables[idx + (VAR_MOMENTUM+0)*nelr] + factor*fluxes[idx + (VAR_MOMENTUM+0)*nelr];
				variables[idx + (VAR_MOMENTUM+1)*nelr] = old_variables[idx + (VAR_MOMENTUM+1)*nelr] + factor*fluxes[idx + (VAR_MOMENTUM+1)*nelr];	
				variables[idx + (VAR_MOMENTUM+2)*nelr] = old_variables[idx + (VAR_MOMENTUM+2)*nelr] + factor*fluxes[idx + (VAR_MOMENTUM+2)*nelr];	
			}
		}
	}

	double end = omp_get_wtime();

	std::cout  << (end-start)  / iterations << " seconds per iteration" << std::endl;

	std::cout << "Saving solution..." << std::endl;
	dump(variables, nel, nelr);
	std::cout << "Saved solution..." << std::endl;


	std::cout << "Cleaning up..." << std::endl;
	delete[] areas;
	delete[] elements_surrounding_elements;
	delete[] normals;

	delete[] variables;
	delete[] old_variables;
	delete[] fluxes;
	delete[] step_factors;

	std::cout << "Done..." << std::endl;

	return 0;
}

// euler3d_cpu.cpp
#include <iostream>
#include <fstream>
#include <omp.h>

// Constants
const float GAMMA = 1.4f;
const int iterations = 2000;
const int NDIM = 3;
const int NNB = 4;
const int RK = 3;  // 3rd order RK
const float ff_mach = 1.2f;
const float deg_angle_of_attack = 0.0f;

// Variables
const int VAR_DENSITY = 0;
const int VAR_MOMENTUM = 1;
const int VAR_DENSITY_ENERGY = (VAR_MOMENTUM + NDIM);
const int NVAR = (VAR_DENSITY_ENERGY + 1);

// Function to compute flux contribution
void compute_flux_contribution(float& density, float momentum[3], float& density_energy, float& pressure, float velocity[3], float fc_momentum_x[3], float fc_momentum_y[3], float fc_momentum_z[3], float fc_density_energy[3]) {
    fc_momentum_x[0] = velocity[0] * momentum[0] + pressure;
    fc_momentum_x[1] = velocity[0] * momentum[1];
    fc_momentum_x[2] = velocity[0] * momentum[2];

    fc_momentum_y[0] = fc_momentum_x[1];
    fc_momentum_y[1] = velocity[1] * momentum[1] + pressure;
    fc_momentum_y[2] = velocity[1] * momentum[2];

    fc_momentum_z[0] = fc_momentum_x[2];
    fc_momentum_z[1] = fc_momentum_y[2];
    fc_momentum_z[2] = velocity[2] * momentum[2] + pressure;

    float de_p = density_energy + pressure;
    fc_density_energy[0] = velocity[0] * de_p;
    fc_density_energy[1] = velocity[1] * de_p;
    fc_density_energy[2] = velocity[2] * de_p;
}

// Function to compute velocity
void compute_velocity(float& density, float momentum[3], float velocity[3]) {
    velocity[0] = momentum[0] / density;
    velocity[1] = momentum[1] / density;
    velocity[2] = momentum[2] / density;
}

// Function to compute speed squared
float compute_speed_sqd(float velocity[3]) {
    return velocity[0] * velocity[0] + velocity[1] * velocity[1] + velocity[2] * velocity[2];
}

// Function to compute pressure
float compute_pressure(float& density, float& density_energy, float& speed_sqd) {
    return (GAMMA - 1.0f) * (density_energy - 0.5f * density * speed_sqd);
}

// Function to compute speed of sound
float compute_speed_of_sound(float& density, float& pressure) {
    return sqrtf(GAMMA * pressure / density);
}

// Function to initialize variables
void initialize_variables(int nelr, float* variables) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        variables[i + VAR_DENSITY * nelr] = 1.4f;
        variables[i + (VAR_MOMENTUM + 0) * nelr] = 0.0f;
        variables[i + (VAR_MOMENTUM + 1) * nelr] = 0.0f;
        variables[i + (VAR_MOMENTUM + 2) * nelr] = 0.0f;
        variables[i + VAR_DENSITY_ENERGY * nelr] = 1.0f;
    }
}

// Function to compute step factor
void compute_step_factor(int nelr, float* variables, float* areas, float* step_factors) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        float density = variables[i + VAR_DENSITY * nelr];
        float momentum[3] = {variables[i + (VAR_MOMENTUM + 0) * nelr], variables[i + (VAR_MOMENTUM + 1) * nelr], variables[i + (VAR_MOMENTUM + 2) * nelr]};
        float density_energy = variables[i + VAR_DENSITY_ENERGY * nelr];

        float velocity[3];
        compute_velocity(density, momentum, velocity);
        float speed_sqd = compute_speed_sqd(velocity);
        float pressure = compute_pressure(density, density_energy, speed_sqd);
        float speed_of_sound = compute_speed_of_sound(density, pressure);

        step_factors[i] = 0.5f / (sqrtf(areas[i]) * (sqrtf(speed_sqd) + speed_of_sound));
    }
}

// Function to compute flux
void compute_flux(int nelr, int* elements_surrounding_elements, float* normals, float* variables, float* fluxes) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        float density_i = variables[i + VAR_DENSITY * nelr];
        float momentum_i[3] = {variables[i + (VAR_MOMENTUM + 0) * nelr], variables[i + (VAR_MOMENTUM + 1) * nelr], variables[i + (VAR_MOMENTUM + 2) * nelr]};
        float density_energy_i = variables[i + VAR_DENSITY_ENERGY * nelr];

        float velocity_i[3];
        compute_velocity(density_i, momentum_i, velocity_i);
        float speed_sqd_i = compute_speed_sqd(velocity_i);
        float speed_i = sqrtf(speed_sqd_i);
        float pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
        float speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);

        float fc_i_momentum_x[3], fc_i_momentum_y[3], fc_i_momentum_z[3];
        float fc_i_density_energy[3];
        compute_flux_contribution(density_i, momentum_i, density_energy_i, pressure_i, velocity_i, fc_i_momentum_x, fc_i_momentum_y, fc_i_momentum_z, fc_i_density_energy);

        float flux_i_density = 0.0f;
        float flux_i_momentum[3] = {0.0f, 0.0f, 0.0f};
        float flux_i_density_energy = 0.0f;

        for (int j = 0; j < NNB; j++) {
            int nb = elements_surrounding_elements[i + j * nelr];
            float normal[3] = {normals[i + (j + 0 * NNB) * nelr], normals[i + (j + 1 * NNB) * nelr], normals[i + (j + 2 * NNB) * nelr]};
            float normal_len = sqrtf(normal[0] * normal[0] + normal[1] * normal[1] + normal[2] * normal[2]);

            if (nb >= 0) {
                float density_nb = variables[nb + VAR_DENSITY * nelr];
                float momentum_nb[3] = {variables[nb + (VAR_MOMENTUM + 0) * nelr], variables[nb + (VAR_MOMENTUM + 1) * nelr], variables[nb + (VAR_MOMENTUM + 2) * nelr]};
                float density_energy_nb = variables[nb + VAR_DENSITY_ENERGY * nelr];

                float velocity_nb[3];
                compute_velocity(density_nb, momentum_nb, velocity_nb);
                float speed_sqd_nb = compute_speed_sqd(velocity_nb);
                float pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
                float speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);

                float fc_nb_momentum_x[3], fc_nb_momentum_y[3], fc_nb_momentum_z[3];
                float fc_nb_density_energy[3];
                compute_flux_contribution(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb, fc_nb_momentum_x, fc_nb_momentum_y, fc_nb_momentum_z, fc_nb_density_energy);

                float factor = -normal_len * 0.2f * 0.5f * (speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                flux_i_density += factor * (density_i - density_nb);
                flux_i_density_energy += factor * (density_energy_i - density_energy_nb);
                flux_i_momentum[0] += factor * (momentum_i[0] - momentum_nb[0]);
                flux_i_momentum[1] += factor * (momentum_i[1] - momentum_nb[1]);
                flux_i_momentum[2] += factor * (momentum_i[2] - momentum_nb[2]);

                factor = 0.5f * normal[0];
                flux_i_density += factor * (momentum_nb[0] + momentum_i[0]);
                flux_i_density_energy += factor * (fc_nb_density_energy[0] + fc_i_density_energy[0]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[0] + fc_i_momentum_x[0]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[0] + fc_i_momentum_y[0]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[0] + fc_i_momentum_z[0]);

                factor = 0.5f * normal[1];
                flux_i_density += factor * (momentum_nb[1] + momentum_i[1]);
                flux_i_density_energy += factor * (fc_nb_density_energy[1] + fc_i_density_energy[1]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[1] + fc_i_momentum_x[1]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[1] + fc_i_momentum_y[1]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[1] + fc_i_momentum_z[1]);

                factor = 0.5f * normal[2];
                flux_i_density += factor * (momentum_nb[2] + momentum_i[2]);
                flux_i_density_energy += factor * (fc_nb_density_energy[2] + fc_i_density_energy[2]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[2] + fc_i_momentum_x[2]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[2] + fc_i_momentum_y[2]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[2] + fc_i_momentum_z[2]);
            } else if (nb == -1) {
                flux_i_momentum[0] += normal[0] * pressure_i;
                flux_i_momentum[1] += normal[1] * pressure_i;
                flux_i_momentum[2] += normal[2] * pressure_i;
            } else if (nb == -2) {
                float factor = 0.5f * normal[0];
                flux_i_density += factor * (0.0f + momentum_i[0]);
                flux_i_density_energy += factor * (0.0f + fc_i_density_energy[0]);
                flux_i_momentum[0] += factor * (0.0f + fc_i_momentum_x[0]);
                flux_i_momentum[1] += factor * (0.0f + fc_i_momentum_y[0]);
                flux_i_momentum[2] += factor * (0.0f + fc_i_momentum_z[0]);

                factor = 0.5f * normal[1];
                flux_i_density += factor * (0.0f + momentum_i[1]);
                flux_i_density_energy += factor * (0.0f + fc_i_density_energy[1]);
                flux_i_momentum[0] += factor * (0.0f + fc_i_momentum_x[1]);
                flux_i_momentum[1] += factor * (0.0f + fc_i_momentum_y[1]);
                flux_i_momentum[2] += factor * (0.0f + fc_i_momentum_z[1]);

                factor = 0.5f * normal[2];
                flux_i_density += factor * (0.0f + momentum_i[2]);
                flux_i_density_energy += factor * (0.0f + fc_i_density_energy[2]);
                flux_i_momentum[0] += factor * (0.0f + fc_i_momentum_x[2]);
                flux_i_momentum[1] += factor * (0.0f + fc_i_momentum_y[2]);
                flux_i_momentum[2] += factor * (0.0f + fc_i_momentum_z[2]);
            }
        }

        fluxes[i + VAR_DENSITY * nelr] = flux_i_density;
        fluxes[i + (VAR_MOMENTUM + 0) * nelr] = flux_i_momentum[0];
        fluxes[i + (VAR_MOMENTUM + 1) * nelr] = flux_i_momentum[1];
        fluxes[i + (VAR_MOMENTUM + 2) * nelr] = flux_i_momentum[2];
        fluxes[i + VAR_DENSITY_ENERGY * nelr] = flux_i_density_energy;
    }
}

// Function to time step
void time_step(int j, int nelr, float* old_variables, float* variables, float* step_factors, float* fluxes) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        float factor = step_factors[i] / (RK + 1 - j);

        variables[i + VAR_DENSITY * nelr] = old_variables[i + VAR_DENSITY * nelr] + factor * fluxes[i + VAR_DENSITY * nelr];
        variables[i + VAR_DENSITY_ENERGY * nelr] = old_variables[i + VAR_DENSITY_ENERGY * nelr] + factor * fluxes[i + VAR_DENSITY_ENERGY * nelr];
        variables[i + (VAR_MOMENTUM + 0) * nelr] = old_variables[i + (VAR_MOMENTUM + 0) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 0) * nelr];
        variables[i + (VAR_MOMENTUM + 1) * nelr] = old_variables[i + (VAR_MOMENTUM + 1) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 1) * nelr];
        variables[i + (VAR_MOMENTUM + 2) * nelr] = old_variables[i + (VAR_MOMENTUM + 2) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 2) * nelr];
    }
}

// Function to dump variables
void dump(float* variables, int nel, int nelr) {
    std::ofstream file("density");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) {
        file << variables[i + VAR_DENSITY * nelr] << std::endl;
    }

    file.close();

    file.open("momentum");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) {
        for (int j = 0; j < NDIM; j++) {
            file << variables[i + (VAR_MOMENTUM + j) * nelr] << " ";
        }
        file << std::endl;
    }

    file.close();

    file.open("density_energy");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) {
        file << variables[i + VAR_DENSITY_ENERGY * nelr] << std::endl;
    }

    file.close();
}

int main(int argc, char** argv) {
    if (argc < 2) {
        std::cout << "Specify data file name" << std::endl;
        return 0;
    }

    const char* data_file_name = argv[1];

    int nel;
    int nelr;

    // Read in domain geometry
    float* areas;
    int* elements_surrounding_elements;
    float* normals;

    std::ifstream file(data_file_name);
    file >> nel;
    nelr = 192 * ((nel / 192) + std::min(1, nel % 192));

    float* h_areas = new float[nelr];
    int* h_elements_surrounding_elements = new int[nelr * NNB];
    float* h_normals = new float[nelr * NDIM * NNB];

    for (int i = 0; i < nel; i++) {
        file >> h_areas[i];
        for (int j = 0; j < NNB; j++) {
            file >> h_elements_surrounding_elements[i + j * nelr];
            if (h_elements_surrounding_elements[i + j * nelr] < 0) {
                h_elements_surrounding_elements[i + j * nelr] = -1;
            }
            h_elements_surrounding_elements[i + j * nelr]--; // Convert to C indexing

            for (int k = 0; k < NDIM; k++) {
                file >> h_normals[i + (j + k * NNB) * nelr];
                h_normals[i + (j + k * NNB) * nelr] = -h_normals[i + (j + k * NNB) * nelr];
            }
        }
    }

    // Fill in remaining data
    int last = nel - 1;
    for (int i = nel; i < nelr; i++) {
        h_areas[i] = h_areas[last];
        for (int j = 0; j < NNB; j++) {
            h_elements_surrounding_elements[i + j * nelr] = h_elements_surrounding_elements[last + j * nelr];
            for (int k = 0; k < NDIM; k++) {
                h_normals[i + (j + k * NNB) * nelr] = h_normals[last + (j + k * NNB) * nelr];
            }
        }
    }

    areas = new float[nelr];
    elements_surrounding_elements = new int[nelr * NNB];
    normals = new float[nelr * NDIM * NNB];

    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        areas[i] = h_areas[i];
    }

    #pragma omp parallel for
    for (int i = 0; i < nelr * NNB; i++) {
        elements_surrounding_elements[i] = h_elements_surrounding_elements[i];
    }

    #pragma omp parallel for
    for (int i = 0; i < nelr * NDIM * NNB; i++) {
        normals[i] = h_normals[i];
    }

    delete[] h_areas;
    delete[] h_elements_surrounding_elements;
    delete[] h_normals;

    // Create arrays and set initial conditions
    float* variables = new float[nelr * NVAR];
    initialize_variables(nelr, variables);

    float* old_variables = new float[nelr * NVAR];
    #pragma omp parallel for
    for (int i = 0; i < nelr * NVAR; i++) {
        old_variables[i] = variables[i];
    }

    float* fluxes = new float[nelr * NVAR];
    #pragma omp parallel for
    for (int i = 0; i < nelr * NVAR; i++) {
        fluxes[i] = 0.0f;
    }

    float* step_factors = new float[nelr];
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        step_factors[i] = 0.0f;
    }

    // Make sure all memory is allocated before we start timing
    #pragma omp parallel for
    for (int i = 0; i < nelr * NVAR; i++) {
        old_variables[i] = variables[i];
    }

    #pragma omp parallel for
    for (int i = 0; i < nelr * NVAR; i++) {
        fluxes[i] = 0.0f;
    }

    // Make sure OpenMP isn't still doing something before we start timing
    omp_set_num_threads(omp_get_max_threads());

    // These need to be computed the first time in order to compute time step
    std::cout << "Starting..." << std::endl;

    double start_time = omp_get_wtime();

    // Begin iterations
    for (int i = 0; i < iterations; i++) {
        #pragma omp parallel for
        for (int j = 0; j < nelr * NVAR; j++) {
            old_variables[j] = variables[j];
        }

        compute_step_factor(nelr, variables, areas, step_factors);

        for (int j = 0; j < RK; j++) {
            compute_flux(nelr, elements_surrounding_elements, normals, variables, fluxes);
            time_step(j, nelr, old_variables, variables, step_factors, fluxes);
        }
    }

    double end_time = omp_get_wtime();

    std::cout << (end_time - start_time) / iterations << " seconds per iteration" << std::endl;

    std::cout << "Saving solution..." << std::endl;
    dump(variables, nel, nelr);
    std::cout << "Saved solution..." << std::endl;

    std::cout << "Cleaning up..." << std::endl;
    delete[] areas;
    delete[] elements_surrounding_elements;
    delete[] normals;

    delete[] variables;
    delete[] old_variables;
    delete[] fluxes;
    delete[] step_factors;

    std::cout << "Done..." << std::endl;

    return 0;
}

#include <iostream>
#include <fstream>
#include <omp.h>

// Constants
const double GAMMA = 1.4;
const int iterations = 2000;
const int NDIM = 3;
const int NNB = 4;
const int RK = 3;  // 3rd order RK
const double ff_mach = 1.2;
const double deg_angle_of_attack = 0.0;

// Variables
const int VAR_DENSITY = 0;
const int VAR_MOMENTUM = 1;
const int VAR_DENSITY_ENERGY = (VAR_MOMENTUM + NDIM);
const int NVAR = (VAR_DENSITY_ENERGY + 1);

// Function to compute flux contribution
void compute_flux_contribution(double& density, double momentum[3], double& density_energy, double& pressure, double velocity[3], double fc_momentum_x[3], double fc_momentum_y[3], double fc_momentum_z[3], double fc_density_energy[3]) {
    fc_momentum_x[0] = velocity[0] * momentum[0] + pressure;
    fc_momentum_x[1] = velocity[0] * momentum[1];
    fc_momentum_x[2] = velocity[0] * momentum[2];

    fc_momentum_y[0] = fc_momentum_x[1];
    fc_momentum_y[1] = velocity[1] * momentum[1] + pressure;
    fc_momentum_y[2] = velocity[1] * momentum[2];

    fc_momentum_z[0] = fc_momentum_x[2];
    fc_momentum_z[1] = fc_momentum_y[2];
    fc_momentum_z[2] = velocity[2] * momentum[2] + pressure;

    double de_p = density_energy + pressure;
    fc_density_energy[0] = velocity[0] * de_p;
    fc_density_energy[1] = velocity[1] * de_p;
    fc_density_energy[2] = velocity[2] * de_p;
}

// Function to compute velocity
void compute_velocity(double& density, double momentum[3], double velocity[3]) {
    velocity[0] = momentum[0] / density;
    velocity[1] = momentum[1] / density;
    velocity[2] = momentum[2] / density;
}

// Function to compute speed squared
double compute_speed_sqd(double velocity[3]) {
    return velocity[0] * velocity[0] + velocity[1] * velocity[1] + velocity[2] * velocity[2];
}

// Function to compute pressure
double compute_pressure(double& density, double& density_energy, double& speed_sqd) {
    return (GAMMA - 1.0) * (density_energy - 0.5 * density * speed_sqd);
}

// Function to compute speed of sound
double compute_speed_of_sound(double& density, double& pressure) {
    return sqrt(GAMMA * pressure / density);
}

// Function to initialize variables
void initialize_variables(int nelr, double* variables) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        variables[i + VAR_DENSITY * nelr] = 1.4;
        variables[i + (VAR_MOMENTUM + 0) * nelr] = 0.0;
        variables[i + (VAR_MOMENTUM + 1) * nelr] = 0.0;
        variables[i + (VAR_MOMENTUM + 2) * nelr] = 0.0;
        variables[i + VAR_DENSITY_ENERGY * nelr] = 1.0;
    }
}

// Function to compute step factor
void compute_step_factor(int nelr, double* variables, double* areas, double* step_factors) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        double density = variables[i + VAR_DENSITY * nelr];
        double momentum[3] = {variables[i + (VAR_MOMENTUM + 0) * nelr], variables[i + (VAR_MOMENTUM + 1) * nelr], variables[i + (VAR_MOMENTUM + 2) * nelr]};
        double density_energy = variables[i + VAR_DENSITY_ENERGY * nelr];

        double velocity[3];
        compute_velocity(density, momentum, velocity);
        double speed_sqd = compute_speed_sqd(velocity);
        double pressure = compute_pressure(density, density_energy, speed_sqd);
        double speed_of_sound = compute_speed_of_sound(density, pressure);

        step_factors[i] = 0.5 / (sqrt(areas[i]) * (sqrt(speed_sqd) + speed_of_sound));
    }
}

// Function to compute flux
void compute_flux(int nelr, int* elements_surrounding_elements, double* normals, double* variables, double* fluxes) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        double density_i = variables[i + VAR_DENSITY * nelr];
        double momentum_i[3] = {variables[i + (VAR_MOMENTUM + 0) * nelr], variables[i + (VAR_MOMENTUM + 1) * nelr], variables[i + (VAR_MOMENTUM + 2) * nelr]};
        double density_energy_i = variables[i + VAR_DENSITY_ENERGY * nelr];

        double velocity_i[3];
        compute_velocity(density_i, momentum_i, velocity_i);
        double speed_sqd_i = compute_speed_sqd(velocity_i);
        double speed_i = sqrt(speed_sqd_i);
        double pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
        double speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);

        double fc_momentum_x[3], fc_momentum_y[3], fc_momentum_z[3], fc_density_energy[3];
        compute_flux_contribution(density_i, momentum_i, density_energy_i, pressure_i, velocity_i, fc_momentum_x, fc_momentum_y, fc_momentum_z, fc_density_energy);

        double flux_i_density = 0.0;
        double flux_i_momentum[3] = {0.0, 0.0, 0.0};
        double flux_i_density_energy = 0.0;

        for (int j = 0; j < NNB; j++) {
            int nb = elements_surrounding_elements[i + j * nelr];
            double normal[3] = {normals[i + (j + 0 * NNB) * nelr], normals[i + (j + 1 * NNB) * nelr], normals[i + (j + 2 * NNB) * nelr]};
            double normal_len = sqrt(normal[0] * normal[0] + normal[1] * normal[1] + normal[2] * normal[2]);

            if (nb >= 0) {
                double density_nb = variables[nb + VAR_DENSITY * nelr];
                double momentum_nb[3] = {variables[nb + (VAR_MOMENTUM + 0) * nelr], variables[nb + (VAR_MOMENTUM + 1) * nelr], variables[nb + (VAR_MOMENTUM + 2) * nelr]};
                double density_energy_nb = variables[nb + VAR_DENSITY_ENERGY * nelr];

                double velocity_nb[3];
                compute_velocity(density_nb, momentum_nb, velocity_nb);
                double speed_sqd_nb = compute_speed_sqd(velocity_nb);
                double pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
                double speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);

                double fc_nb_momentum_x[3], fc_nb_momentum_y[3], fc_nb_momentum_z[3], fc_nb_density_energy[3];
                compute_flux_contribution(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb, fc_nb_momentum_x, fc_nb_momentum_y, fc_nb_momentum_z, fc_nb_density_energy);

                double factor = -normal_len * 0.2 * 0.5 * (speed_i + sqrt(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                flux_i_density += factor * (density_i - density_nb);
                flux_i_density_energy += factor * (density_energy_i - density_energy_nb);
                flux_i_momentum[0] += factor * (momentum_i[0] - momentum_nb[0]);
                flux_i_momentum[1] += factor * (momentum_i[1] - momentum_nb[1]);
                flux_i_momentum[2] += factor * (momentum_i[2] - momentum_nb[2]);

                factor = 0.5 * normal[0];
                flux_i_density += factor * (momentum_nb[0] + momentum_i[0]);
                flux_i_density_energy += factor * (fc_nb_density_energy[0] + fc_density_energy[0]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[0] + fc_momentum_x[0]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[0] + fc_momentum_y[0]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[0] + fc_momentum_z[0]);

                factor = 0.5 * normal[1];
                flux_i_density += factor * (momentum_nb[1] + momentum_i[1]);
                flux_i_density_energy += factor * (fc_nb_density_energy[1] + fc_density_energy[1]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[1] + fc_momentum_x[1]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[1] + fc_momentum_y[1]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[1] + fc_momentum_z[1]);

                factor = 0.5 * normal[2];
                flux_i_density += factor * (momentum_nb[2] + momentum_i[2]);
                flux_i_density_energy += factor * (fc_nb_density_energy[2] + fc_density_energy[2]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[2] + fc_momentum_x[2]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[2] + fc_momentum_y[2]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[2] + fc_momentum_z[2]);
            } else if (nb == -1) {
                flux_i_momentum[0] += normal[0] * pressure_i;
                flux_i_momentum[1] += normal[1] * pressure_i;
                flux_i_momentum[2] += normal[2] * pressure_i;
            } else if (nb == -2) {
                double ff_variable[5] = {1.4, 0.0, 0.0, 0.0, 1.0};
                double ff_momentum[3] = {ff_variable[1], ff_variable[2], ff_variable[3]};
                double ff_density_energy = ff_variable[4];

                double ff_velocity[3];
                compute_velocity(ff_variable[0], ff_momentum, ff_velocity);
                double ff_speed_sqd = compute_speed_sqd(ff_velocity);
                double ff_pressure = compute_pressure(ff_variable[0], ff_density_energy, ff_speed_sqd);
                double ff_speed_of_sound = compute_speed_of_sound(ff_variable[0], ff_pressure);

                double ff_fc_momentum_x[3], ff_fc_momentum_y[3], ff_fc_momentum_z[3], ff_fc_density_energy[3];
                compute_flux_contribution(ff_variable[0], ff_momentum, ff_density_energy, ff_pressure, ff_velocity, ff_fc_momentum_x, ff_fc_momentum_y, ff_fc_momentum_z, ff_fc_density_energy);

                double factor = 0.5 * normal[0];
                flux_i_density += factor * (ff_momentum[0] + momentum_i[0]);
                flux_i_density_energy += factor * (ff_fc_density_energy[0] + fc_density_energy[0]);
                flux_i_momentum[0] += factor * (ff_fc_momentum_x[0] + fc_momentum_x[0]);
                flux_i_momentum[1] += factor * (ff_fc_momentum_y[0] + fc_momentum_y[0]);
                flux_i_momentum[2] += factor * (ff_fc_momentum_z[0] + fc_momentum_z[0]);

                factor = 0.5 * normal[1];
                flux_i_density += factor * (ff_momentum[1] + momentum_i[1]);
                flux_i_density_energy += factor * (ff_fc_density_energy[1] + fc_density_energy[1]);
                flux_i_momentum[0] += factor * (ff_fc_momentum_x[1] + fc_momentum_x[1]);
                flux_i_momentum[1] += factor * (ff_fc_momentum_y[1] + fc_momentum_y[1]);
                flux_i_momentum[2] += factor * (ff_fc_momentum_z[1] + fc_momentum_z[1]);

                factor = 0.5 * normal[2];
                flux_i_density += factor * (ff_momentum[2] + momentum_i[2]);
                flux_i_density_energy += factor * (ff_fc_density_energy[2] + fc_density_energy[2]);
                flux_i_momentum[0] += factor * (ff_fc_momentum_x[2] + fc_momentum_x[2]);
                flux_i_momentum[1] += factor * (ff_fc_momentum_y[2] + fc_momentum_y[2]);
                flux_i_momentum[2] += factor * (ff_fc_momentum_z[2] + fc_momentum_z[2]);
            }
        }

        fluxes[i + VAR_DENSITY * nelr] = flux_i_density;
        fluxes[i + (VAR_MOMENTUM + 0) * nelr] = flux_i_momentum[0];
        fluxes[i + (VAR_MOMENTUM + 1) * nelr] = flux_i_momentum[1];
        fluxes[i + (VAR_MOMENTUM + 2) * nelr] = flux_i_momentum[2];
        fluxes[i + VAR_DENSITY_ENERGY * nelr] = flux_i_density_energy;
    }
}

// Function to time step
void time_step(int j, int nelr, double* old_variables, double* variables, double* step_factors, double* fluxes) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        double factor = step_factors[i] / (RK + 1 - j);

        variables[i + VAR_DENSITY * nelr] = old_variables[i + VAR_DENSITY * nelr] + factor * fluxes[i + VAR_DENSITY * nelr];
        variables[i + VAR_DENSITY_ENERGY * nelr] = old_variables[i + VAR_DENSITY_ENERGY * nelr] + factor * fluxes[i + VAR_DENSITY_ENERGY * nelr];
        variables[i + (VAR_MOMENTUM + 0) * nelr] = old_variables[i + (VAR_MOMENTUM + 0) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 0) * nelr];
        variables[i + (VAR_MOMENTUM + 1) * nelr] = old_variables[i + (VAR_MOMENTUM + 1) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 1) * nelr];
        variables[i + (VAR_MOMENTUM + 2) * nelr] = old_variables[i + (VAR_MOMENTUM + 2) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 2) * nelr];
    }
}

// Function to dump variables
void dump(double* variables, int nel, int nelr) {
    std::ofstream file("density");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) file << variables[i + VAR_DENSITY * nelr] << std::endl;

    file.close();

    file.open("momentum");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) {
        for (int j = 0; j < NDIM; j++) file << variables[i + (VAR_MOMENTUM + j) * nelr] << " ";
        file << std::endl;
    }

    file.close();

    file.open("density_energy");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) file << variables[i + VAR_DENSITY_ENERGY * nelr] << std::endl;
}

int main(int argc, char** argv) {
    if (argc < 2) {
        std::cout << "Specify data file name" << std::endl;
        return 0;
    }

    const char* data_file_name = argv[1];

    int nel;
    int nelr;

    // Read in domain geometry
    double* areas;
    int* elements_surrounding_elements;
    double* normals;

    std::ifstream file(data_file_name);

    file >> nel;
    nelr = 192 * ((nel / 192) + (nel % 192 != 0));

    double* h_areas = new double[nelr];
    int* h_elements_surrounding_elements = new int[nelr * NNB];
    double* h_normals = new double[nelr * NDIM * NNB];

    // Read in data
    for (int i = 0; i < nel; i++) {
        file >> h_areas[i];
        for (int j = 0; j < NNB; j++) {
            file >> h_elements_surrounding_elements[i + j * nelr];
            if (h_elements_surrounding_elements[i + j * nelr] < 0) h_elements_surrounding_elements[i + j * nelr] = -1;
            h_elements_surrounding_elements[i + j * nelr]--;  // it's coming in with Fortran numbering

            for (int k = 0; k < NDIM; k++) {
                file >> h_normals[i + (j + k * NNB) * nelr];
                h_normals[i + (j + k * NNB) * nelr] = -h_normals[i + (j + k * NNB) * nelr];
            }
        }
    }

    // Fill in remaining data
    int last = nel - 1;
    for (int i = nel; i < nelr; i++) {
        h_areas[i] = h_areas[last];
        for (int j = 0; j < NNB; j++) {
            // Duplicate the last element
            h_elements_surrounding_elements[i + j * nelr] = h_elements_surrounding_elements[last + j * nelr];
            for (int k = 0; k < NDIM; k++) h_normals[last + (j + k * NNB) * nelr] = h_normals[last + (j + k * NNB) * nelr];
        }
    }

    areas = new double[nelr];
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        areas[i] = h_areas[i];
    }

    elements_surrounding_elements = new int[nelr * NNB];
    #pragma omp parallel for
    for (int i = 0; i < nelr * NNB; i++) {
        elements_surrounding_elements[i] = h_elements_surrounding_elements[i];
    }

    normals = new double[nelr * NDIM * NNB];
    #pragma omp parallel for
    for (int i = 0; i < nelr * NDIM * NNB; i++) {
        normals[i] = h_normals[i];
    }

    delete[] h_areas;
    delete[] h_elements_surrounding_elements;
    delete[] h_normals;

    // Create arrays and set initial conditions
    double* variables = new double[nelr * NVAR];
    initialize_variables(nelr, variables);

    double* old_variables = new double[nelr * NVAR];
    #pragma omp parallel for
    for (int i = 0; i < nelr * NVAR; i++) {
        old_variables[i] = variables[i];
    }

    double* fluxes = new double[nelr * NVAR];
    #pragma omp parallel for
    for (int i = 0; i < nelr * NVAR; i++) {
        fluxes[i] = 0.0;
    }

    double* step_factors = new double[nelr];
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        step_factors[i] = 0.0;
    }

    // Make sure all memory is allocated before we start timing
    #pragma omp parallel for
    for (int i = 0; i < nelr * NVAR; i++) {
        old_variables[i] = variables[i];
    }

    #pragma omp parallel for
    for (int i = 0; i < nelr * NVAR; i++) {
        fluxes[i] = 0.0;
    }

    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        step_factors[i] = 0.0;
    }

    // Start timing
    double start_time = omp_get_wtime();

    // Begin iterations
    for (int i = 0; i < iterations; i++) {
        #pragma omp parallel for
        for (int j = 0; j < nelr * NVAR; j++) {
            old_variables[j] = variables[j];
        }

        compute_step_factor(nelr, variables, areas, step_factors);

        for (int j = 0; j < RK; j++) {
            compute_flux(nelr, elements_surrounding_elements, normals, variables, fluxes);
            time_step(j, nelr, old_variables, variables, step_factors, fluxes);
        }
    }

    // Stop timing
    double end_time = omp_get_wtime();

    std::cout << "Time per iteration: " << (end_time - start_time) / iterations << std::endl;

    // Save solution
    dump(variables, nel, nelr);

    // Clean up
    delete[] areas;
    delete[] elements_surrounding_elements;
    delete[] normals;
    delete[] variables;
    delete[] old_variables;
    delete[] fluxes;
    delete[] step_factors;

    return 0;
}

// euler3d_cpu.cpp
#include <iostream>
#include <fstream>
#include <cmath>
#include <omp.h>

// Constants
const double GAMMA = 1.4;
const int iterations = 2000;
const int block_length = 192;
const int NDIM = 3;
const int NNB = 4;
const int RK = 3;  // 3rd order RK
const double ff_mach = 1.2;
const double deg_angle_of_attack = 0.0;

// Variables
const int VAR_DENSITY = 0;
const int VAR_MOMENTUM = 1;
const int VAR_DENSITY_ENERGY = (VAR_MOMENTUM + NDIM);
const int NVAR = (VAR_DENSITY_ENERGY + 1);

// Function to compute flux contribution
void compute_flux_contribution(double& density, double momentum[3], double& density_energy, double& pressure, double velocity[3], double fc_momentum_x[3], double fc_momentum_y[3], double fc_momentum_z[3], double fc_density_energy[3]) {
    fc_momentum_x[0] = velocity[0] * momentum[0] + pressure;
    fc_momentum_x[1] = velocity[0] * momentum[1];
    fc_momentum_x[2] = velocity[0] * momentum[2];

    fc_momentum_y[0] = fc_momentum_x[1];
    fc_momentum_y[1] = velocity[1] * momentum[1] + pressure;
    fc_momentum_y[2] = velocity[1] * momentum[2];

    fc_momentum_z[0] = fc_momentum_x[2];
    fc_momentum_z[1] = fc_momentum_y[2];
    fc_momentum_z[2] = velocity[2] * momentum[2] + pressure;

    double de_p = density_energy + pressure;
    fc_density_energy[0] = velocity[0] * de_p;
    fc_density_energy[1] = velocity[1] * de_p;
    fc_density_energy[2] = velocity[2] * de_p;
}

// Function to compute velocity
void compute_velocity(double& density, double momentum[3], double velocity[3]) {
    velocity[0] = momentum[0] / density;
    velocity[1] = momentum[1] / density;
    velocity[2] = momentum[2] / density;
}

// Function to compute speed squared
double compute_speed_sqd(double velocity[3]) {
    return velocity[0] * velocity[0] + velocity[1] * velocity[1] + velocity[2] * velocity[2];
}

// Function to compute pressure
double compute_pressure(double& density, double& density_energy, double& speed_sqd) {
    return (GAMMA - 1.0) * (density_energy - 0.5 * density * speed_sqd);
}

// Function to compute speed of sound
double compute_speed_of_sound(double& density, double& pressure) {
    return sqrt(GAMMA * pressure / density);
}

// Function to initialize variables
void initialize_variables(int nelr, double* variables) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        variables[i + VAR_DENSITY * nelr] = 1.4;
        variables[i + (VAR_MOMENTUM + 0) * nelr] = 0.0;
        variables[i + (VAR_MOMENTUM + 1) * nelr] = 0.0;
        variables[i + (VAR_MOMENTUM + 2) * nelr] = 0.0;
        variables[i + VAR_DENSITY_ENERGY * nelr] = 1.0;
    }
}

// Function to compute step factor
void compute_step_factor(int nelr, double* variables, double* areas, double* step_factors) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        double density = variables[i + VAR_DENSITY * nelr];
        double momentum[3] = {variables[i + (VAR_MOMENTUM + 0) * nelr], variables[i + (VAR_MOMENTUM + 1) * nelr], variables[i + (VAR_MOMENTUM + 2) * nelr]};
        double density_energy = variables[i + VAR_DENSITY_ENERGY * nelr];

        double velocity[3];
        compute_velocity(density, momentum, velocity);
        double speed_sqd = compute_speed_sqd(velocity);
        double pressure = compute_pressure(density, density_energy, speed_sqd);
        double speed_of_sound = compute_speed_of_sound(density, pressure);

        step_factors[i] = 0.5 / (sqrt(areas[i]) * (sqrt(speed_sqd) + speed_of_sound));
    }
}

// Function to compute flux
void compute_flux(int nelr, int* elements_surrounding_elements, double* normals, double* variables, double* fluxes) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        int j, nb;
        double normal[3];
        double normal_len;
        double factor;

        double density_i = variables[i + VAR_DENSITY * nelr];
        double momentum_i[3] = {variables[i + (VAR_MOMENTUM + 0) * nelr], variables[i + (VAR_MOMENTUM + 1) * nelr], variables[i + (VAR_MOMENTUM + 2) * nelr]};
        double density_energy_i = variables[i + VAR_DENSITY_ENERGY * nelr];

        double velocity_i[3];
        compute_velocity(density_i, momentum_i, velocity_i);
        double speed_sqd_i = compute_speed_sqd(velocity_i);
        double speed_i = sqrt(speed_sqd_i);
        double pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
        double speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);

        double fc_i_momentum_x[3], fc_i_momentum_y[3], fc_i_momentum_z[3];
        double fc_i_density_energy[3];
        compute_flux_contribution(density_i, momentum_i, density_energy_i, pressure_i, velocity_i, fc_i_momentum_x, fc_i_momentum_y, fc_i_momentum_z, fc_i_density_energy);

        double flux_i_density = 0.0;
        double flux_i_momentum[3] = {0.0, 0.0, 0.0};
        double flux_i_density_energy = 0.0;

        for (j = 0; j < NNB; j++) {
            nb = elements_surrounding_elements[i + j * nelr];
            normal[0] = normals[i + (j + 0 * NNB) * nelr];
            normal[1] = normals[i + (j + 1 * NNB) * nelr];
            normal[2] = normals[i + (j + 2 * NNB) * nelr];
            normal_len = sqrt(normal[0] * normal[0] + normal[1] * normal[1] + normal[2] * normal[2]);

            if (0 <= nb) {  // a legitimate neighbor
                double density_nb = variables[nb + VAR_DENSITY * nelr];
                double momentum_nb[3] = {variables[nb + (VAR_MOMENTUM + 0) * nelr], variables[nb + (VAR_MOMENTUM + 1) * nelr], variables[nb + (VAR_MOMENTUM + 2) * nelr]};
                double density_energy_nb = variables[nb + VAR_DENSITY_ENERGY * nelr];

                double velocity_nb[3];
                compute_velocity(density_nb, momentum_nb, velocity_nb);
                double speed_sqd_nb = compute_speed_sqd(velocity_nb);
                double pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
                double speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);

                double fc_nb_momentum_x[3], fc_nb_momentum_y[3], fc_nb_momentum_z[3];
                double fc_nb_density_energy[3];
                compute_flux_contribution(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb, fc_nb_momentum_x, fc_nb_momentum_y, fc_nb_momentum_z, fc_nb_density_energy);

                // artificial viscosity
                factor = -normal_len * 0.2 * 0.5 * (speed_i + sqrt(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                flux_i_density += factor * (density_i - density_nb);
                flux_i_density_energy += factor * (density_energy_i - density_energy_nb);
                flux_i_momentum[0] += factor * (momentum_i[0] - momentum_nb[0]);
                flux_i_momentum[1] += factor * (momentum_i[1] - momentum_nb[1]);
                flux_i_momentum[2] += factor * (momentum_i[2] - momentum_nb[2]);

                // accumulate cell-centered fluxes
                factor = 0.5 * normal[0];
                flux_i_density += factor * (momentum_nb[0] + momentum_i[0]);
                flux_i_density_energy += factor * (fc_nb_density_energy[0] + fc_i_density_energy[0]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[0] + fc_i_momentum_x[0]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[0] + fc_i_momentum_y[0]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[0] + fc_i_momentum_z[0]);

                factor = 0.5 * normal[1];
                flux_i_density += factor * (momentum_nb[1] + momentum_i[1]);
                flux_i_density_energy += factor * (fc_nb_density_energy[1] + fc_i_density_energy[1]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[1] + fc_i_momentum_x[1]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[1] + fc_i_momentum_y[1]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[1] + fc_i_momentum_z[1]);

                factor = 0.5 * normal[2];
                flux_i_density += factor * (momentum_nb[2] + momentum_i[2]);
                flux_i_density_energy += factor * (fc_nb_density_energy[2] + fc_i_density_energy[2]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[2] + fc_i_momentum_x[2]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[2] + fc_i_momentum_y[2]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[2] + fc_i_momentum_z[2]);
            } else if (-1 == nb) {  // a wing boundary
                flux_i_momentum[0] += normal[0] * pressure_i;
                flux_i_momentum[1] += normal[1] * pressure_i;
                flux_i_momentum[2] += normal[2] * pressure_i;
            } else if (-2 == nb) {  // a far field boundary
                // far field conditions
                double ff_density = 1.4;
                double ff_momentum[3] = {0.0, 0.0, 0.0};
                double ff_density_energy = 1.0;

                double ff_velocity[3];
                compute_velocity(ff_density, ff_momentum, ff_velocity);
                double ff_speed_sqd = compute_speed_sqd(ff_velocity);
                double ff_pressure = compute_pressure(ff_density, ff_density_energy, ff_speed_sqd);

                double ff_fc_momentum_x[3], ff_fc_momentum_y[3], ff_fc_momentum_z[3];
                double ff_fc_density_energy[3];
                compute_flux_contribution(ff_density, ff_momentum, ff_density_energy, ff_pressure, ff_velocity, ff_fc_momentum_x, ff_fc_momentum_y, ff_fc_momentum_z, ff_fc_density_energy);

                factor = 0.5 * normal[0];
                flux_i_density += factor * (ff_momentum[0] + momentum_i[0]);
                flux_i_density_energy += factor * (ff_fc_density_energy[0] + fc_i_density_energy[0]);
                flux_i_momentum[0] += factor * (ff_fc_momentum_x[0] + fc_i_momentum_x[0]);
                flux_i_momentum[1] += factor * (ff_fc_momentum_y[0] + fc_i_momentum_y[0]);
                flux_i_momentum[2] += factor * (ff_fc_momentum_z[0] + fc_i_momentum_z[0]);

                factor = 0.5 * normal[1];
                flux_i_density += factor * (ff_momentum[1] + momentum_i[1]);
                flux_i_density_energy += factor * (ff_fc_density_energy[1] + fc_i_density_energy[1]);
                flux_i_momentum[0] += factor * (ff_fc_momentum_x[1] + fc_i_momentum_x[1]);
                flux_i_momentum[1] += factor * (ff_fc_momentum_y[1] + fc_i_momentum_y[1]);
                flux_i_momentum[2] += factor * (ff_fc_momentum_z[1] + fc_i_momentum_z[1]);

                factor = 0.5 * normal[2];
                flux_i_density += factor * (ff_momentum[2] + momentum_i[2]);
                flux_i_density_energy += factor * (ff_fc_density_energy[2] + fc_i_density_energy[2]);
                flux_i_momentum[0] += factor * (ff_fc_momentum_x[2] + fc_i_momentum_x[2]);
                flux_i_momentum[1] += factor * (ff_fc_momentum_y[2] + fc_i_momentum_y[2]);
                flux_i_momentum[2] += factor * (ff_fc_momentum_z[2] + fc_i_momentum_z[2]);
            }
        }

        fluxes[i + VAR_DENSITY * nelr] = flux_i_density;
        fluxes[i + (VAR_MOMENTUM + 0) * nelr] = flux_i_momentum[0];
        fluxes[i + (VAR_MOMENTUM + 1) * nelr] = flux_i_momentum[1];
        fluxes[i + (VAR_MOMENTUM + 2) * nelr] = flux_i_momentum[2];
        fluxes[i + VAR_DENSITY_ENERGY * nelr] = flux_i_density_energy;
    }
}

// Function to time step
void time_step(int j, int nelr, double* old_variables, double* variables, double* step_factors, double* fluxes) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        double factor = step_factors[i] / (RK + 1 - j);

        variables[i + VAR_DENSITY * nelr] = old_variables[i + VAR_DENSITY * nelr] + factor * fluxes[i + VAR_DENSITY * nelr];
        variables[i + VAR_DENSITY_ENERGY * nelr] = old_variables[i + VAR_DENSITY_ENERGY * nelr] + factor * fluxes[i + VAR_DENSITY_ENERGY * nelr];
        variables[i + (VAR_MOMENTUM + 0) * nelr] = old_variables[i + (VAR_MOMENTUM + 0) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 0) * nelr];
        variables[i + (VAR_MOMENTUM + 1) * nelr] = old_variables[i + (VAR_MOMENTUM + 1) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 1) * nelr];
        variables[i + (VAR_MOMENTUM + 2) * nelr] = old_variables[i + (VAR_MOMENTUM + 2) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 2) * nelr];
    }
}

// Function to dump variables
void dump(double* variables, int nel, int nelr) {
    std::ofstream file("density");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) {
        file << variables[i + VAR_DENSITY * nelr] << std::endl;
    }

    file.close();

    file.open("momentum");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) {
        file << variables[i + (VAR_MOMENTUM + 0) * nelr] << " " << variables[i + (VAR_MOMENTUM + 1) * nelr] << " " << variables[i + (VAR_MOMENTUM + 2) * nelr] << std::endl;
    }

    file.close();

    file.open("density_energy");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) {
        file << variables[i + VAR_DENSITY_ENERGY * nelr] << std::endl;
    }

    file.close();
}

int main(int argc, char** argv) {
    if (argc < 2) {
        std::cout << "Specify data file name" << std::endl;
        return 0;
    }

    const char* data_file_name = argv[1];

    int nel;
    int nelr;

    // Read in domain geometry
    double* areas;
    int* elements_surrounding_elements;
    double* normals;

    std::ifstream file(data_file_name);
    file >> nel;
    nelr = block_length * ((nel / block_length) + std::min(1, nel % block_length));

    double* h_areas = new double[nelr];
    int* h_elements_surrounding_elements = new int[nelr * NNB];
    double* h_normals = new double[nelr * NDIM * NNB];

    // Read in data
    for (int i = 0; i < nel; i++) {
        file >> h_areas[i];
        for (int j = 0; j < NNB; j++) {
            file >> h_elements_surrounding_elements[i + j * nelr];
            if (h_elements_surrounding_elements[i + j * nelr] < 0) {
                h_elements_surrounding_elements[i + j * nelr] = -1;
            }
            h_elements_surrounding_elements[i + j * nelr]--;  // it's coming in with Fortran numbering

            for (int k = 0; k < NDIM; k++) {
                file >> h_normals[i + (j + k * NNB) * nelr];
                h_normals[i + (j + k * NNB) * nelr] = -h_normals[i + (j + k * NNB) * nelr];
            }
        }
    }

    // Fill in remaining data
    int last = nel - 1;
    for (int i = nel; i < nelr; i++) {
        h_areas[i] = h_areas[last];
        for (int j = 0; j < NNB; j++) {
            // Duplicate the last element
            h_elements_surrounding_elements[i + j * nelr] = h_elements_surrounding_elements[last + j * nelr];
            for (int k = 0; k < NDIM; k++) {
                h_normals[last + (j + k * NNB) * nelr] = h_normals[last + (j + k * NNB) * nelr];
            }
        }
    }

    areas = new double[nelr];
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        areas[i] = h_areas[i];
    }

    elements_surrounding_elements = new int[nelr * NNB];
    #pragma omp parallel for
    for (int i = 0; i < nelr * NNB; i++) {
        elements_surrounding_elements[i] = h_elements_surrounding_elements[i];
    }

    normals = new double[nelr * NDIM * NNB];
    #pragma omp parallel for
    for (int i = 0; i < nelr * NDIM * NNB; i++) {
        normals[i] = h_normals[i];
    }

    delete[] h_areas;
    delete[] h_elements_surrounding_elements;
    delete[] h_normals;

    // Create arrays and set initial conditions
    double* variables = new double[nelr * NVAR];
    initialize_variables(nelr, variables);

    double* old_variables = new double[nelr * NVAR];
    #pragma omp parallel for
    for (int i = 0; i < nelr * NVAR; i++) {
        old_variables[i] = variables[i];
    }

    double* fluxes = new double[nelr * NVAR];
    #pragma omp parallel for
    for (int i = 0; i < nelr * NVAR; i++) {
        fluxes[i] = 0.0;
    }

    double* step_factors = new double[nelr];
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        step_factors[i] = 0.0;
    }

    // Make sure all memory is allocated before we start timing
    #pragma omp parallel for
    for (int i = 0; i < nelr * NVAR; i++) {
        old_variables[i] = variables[i];
    }

    #pragma omp parallel for
    for (int i = 0; i < nelr * NVAR; i++) {
        fluxes[i] = 0.0;
    }

    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        step_factors[i] = 0.0;
    }

    // Start timing
    double start_time = omp_get_wtime();

    // Begin iterations
    for (int i = 0; i < iterations; i++) {
        #pragma omp parallel for
        for (int j = 0; j < nelr * NVAR; j++) {
            old_variables[j] = variables[j];
        }

        compute_step_factor(nelr, variables, areas, step_factors);

        for (int j = 0; j < RK; j++) {
            compute_flux(nelr, elements_surrounding_elements, normals, variables, fluxes);
            time_step(j, nelr, old_variables, variables, step_factors, fluxes);
        }
    }

    // Stop timing
    double end_time = omp_get_wtime();

    std::cout << "Time per iteration: " << (end_time - start_time) / iterations << std::endl;

    // Save solution
    dump(variables, nel, nelr);

    // Clean up
    delete[] areas;
    delete[] elements_surrounding_elements;
    delete[] normals;
    delete[] variables;
    delete[] old_variables;
    delete[] fluxes;
    delete[] step_factors;

    return 0;
}

