#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void calculate_temp(int iteration, float *power, float *temp_src, float *temp_dst, int grid_cols, int grid_rows, int border_cols, int border_rows, float Cap, float Rx, float Ry, float Rz, float step, float time_elapsed){
	int i, j;
	for (i = 0; i < grid_rows; i++) {
		for (j = 0; j < grid_cols; j++) {
			int index = grid_cols * i + j;
			if (i >= border_rows && i < grid_rows - border_rows && j >= border_cols && j < grid_cols - border_cols) {
				temp_dst[index] = temp_src[index] + step / Cap * (power[index] + (temp_src[(i + 1) * grid_cols + j] + temp_src[(i - 1) * grid_cols + j] - 2.0 * temp_src[index]) * Ry + (temp_src[i * grid_cols + j + 1] + temp_src[i * grid_cols + j - 1] - 2.0 * temp_src[index]) * Rx + (amb_temp - temp_src[index]) * Rz);
			}
		}
	}
}

int compute_tran_temp(float *MatrixPower, float *MatrixTemp[2], int col, int row, int total_iterations, int num_iterations, int borderCols, int borderRows) {
	float grid_height = chip_height / row;
	float grid_width = chip_width / col;

	float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
	float Rx = grid_width / (2.0 * K_SI * t_chip * grid_height);
	float Ry = grid_height / (2.0 * K_SI * t_chip * grid_width);
	float Rz = t_chip / (K_SI * grid_height * grid_width);

	float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
	float step = PRECISION / max_slope;
	float t;
	float time_elapsed = 0.001;

	int src = 1, dst = 0;

	for (t = 0; t < total_iterations; t += num_iterations) {
		int temp = src;
		src = dst;
		dst = temp;
		for (int iter = 0; iter < MIN(num_iterations, total_iterations - t); iter++) {
			#pragma omp parallel for
			for (int i = borderRows; i < row - borderRows; i++) {
				for (int j = borderCols; j < col - borderCols; j++) {
					int index = col * i + j;
					MatrixTemp[dst][index] = MatrixTemp[src][index] + step / Cap * (MatrixPower[index] + (MatrixTemp[src][(i + 1) * col + j] + MatrixTemp[src][(i - 1) * col + j] - 2.0 * MatrixTemp[src][index]) * Ry + (MatrixTemp[src][i * col + j + 1] + MatrixTemp[src][i * col + j - 1] - 2.0 * MatrixTemp[src][index]) * Rx + (amb_temp - MatrixTemp[src][index]) * Rz);
				}
			}
			int temp2 = src;
			src = dst;
			dst = temp2;
		}
	}
	return dst;
}

