    int i;
    for (i = 0; i < numiter; ++i) {
        #pragma omp parallel for
        for (int z = 0; z < nz; z++) {
            for (int y = 0; y < ny; y++) {
                for (int x = 0; x < nx; x++) {
                    int c = x + y * nx + z * nx * ny;
