#include <math.h>
#include <float.h>
#include <omp.h>

#include "kmeans.h"

#define THREADS_PER_DIM 16
#define BLOCKS_PER_DIM 16
#define THREADS_PER_BLOCK THREADS_PER_DIM*THREADS_PER_DIM

/* GLOBAL!!!!!! */
unsigned int num_threads_perdim = THREADS_PER_DIM;					/* sqrt(256) -- see references for this choice */
unsigned int num_blocks_perdim = BLOCKS_PER_DIM;					/* temporary */
unsigned int num_threads = num_threads_perdim*num_threads_perdim;	/* number of threads */
unsigned int num_blocks = num_blocks_perdim*num_blocks_perdim;		/* number of blocks */

/* _d denotes it resides on the device */
int    *membership_new;												/* newly assignment membership */
float  *feature;													/* original data array */
int    *membership;												/* membership on the host */
float  *clusters;													/* cluster centers on the host */
float  *block_clusters;												/* per block calculation of cluster centers */
int    *block_deltas;												/* per block calculation of deltas */


/* -------------- allocateMemory() ------------------- */
/* allocate host memory, calculate number of blocks and threads */
void allocateMemory(int npoints, int nfeatures, int nclusters, float **features)
{	
	num_blocks = npoints / num_threads;
	if (0 < npoints % num_threads)		/* defeat truncation */
		num_blocks++;

	num_blocks_perdim = sqrt((double) num_blocks);
	while (num_blocks > num_blocks_perdim * num_blocks_perdim)	// defeat truncation (should run once)
		num_blocks_perdim++;

	num_blocks = num_blocks_perdim*num_blocks_perdim;

	/* allocate memory for memory_new[] and initialize to -1 (host) */
	membership_new = (int*) malloc(npoints * sizeof(int));
	for(int i=0;npoints > i;i++) {
		membership_new[i] = -1;
	}

	/* allocate memory for feature[] (host) */
	feature = (float *) malloc(npoints*nfeatures*sizeof(float));
	for(int i=0; i<npoints; i++) {
		for(int j=0; j<nfeatures; j++) {
			feature[i*nfeatures + j] = features[0][i*nfeatures + j];
		}
	}

	/* allocate memory for membership[] (host) */
	membership = (int *) malloc(npoints*sizeof(int));

	/* allocate memory for clusters[] (host) */
	clusters = (float *) malloc(nclusters*nfeatures*sizeof(float));

	/* allocate memory for block_clusters[] (host) */
	block_clusters = (float *) malloc(num_blocks_perdim * num_blocks_perdim * nclusters * nfeatures * sizeof(float));

	/* allocate memory for block_deltas[] (host) */
	block_deltas = (int *) malloc(num_blocks_perdim * num_blocks_perdim * sizeof(int));
}

/* -------------- deallocateMemory() ------------------- */
/* free host memory */
void deallocateMemory()
{
	free(membership_new);
	free(feature);
	free(membership);
	free(clusters);
	free(block_clusters);
	free(block_deltas);
}

/* ------------------- kmeansPoint() --------------------- */
/* find the index of nearest cluster centers and change membership*/
void kmeansPoint(float  *features,			/* in: [npoints*nfeatures] */
            int     nfeatures,
            int     npoints,
            int     nclusters,
            int    *membership,
			float  *clusters,
			float  *block_clusters,
			int    *block_deltas) 
{
	int  index = -1;

	#pragma omp parallel for \
                shared(features, membership, clusters, block_clusters, block_deltas) \
                firstprivate(npoints, nfeatures, nclusters) \
                private(index)
	for (int point_id = 0; point_id < npoints; point_id++)
	{
		int i, j;
		float min_dist = FLT_MAX;
		float dist;													/* distance square between a point to cluster center */

		/* find the cluster center id with min distance to pt */
		for (i=0; nclusters > i; i++) {
			int cluster_base_index = i*nfeatures;					/* base index of cluster centers for inverted array */			
			float ans=0.0;												/* Euclidean distance sqaure */

			for (j=0; nfeatures > j; j++)
			{					
				int addr = point_id + j*npoints;					/* appropriate index of data point */
				float diff = (features[addr] -
							  clusters[cluster_base_index + j]);	/* distance between a data point to cluster centers */
				ans = ans + (diff*diff);									/* sum of squares */
			}
			dist = ans;		

			/* see if distance is smaller than previous ones:
			if so, change minimum distance and save index of cluster center */
			if (min_dist > dist) {
				min_dist = dist;
				index    = i;
			}
		}
	}

	#pragma omp parallel for \
                shared(features, membership, clusters, block_clusters, block_deltas) \
                firstprivate(npoints, nfeatures, nclusters) \
                private(index)
	for (int point_id = 0; point_id < npoints; point_id++)
	{
		int i, j;
		int cluster_id = -1;

		/* find the cluster center id with min distance to pt */
		for (i=0; nclusters > i; i++) {
			int cluster_base_index = i*nfeatures;					/* base index of cluster centers for inverted array */			
			float ans=0.0;												/* Euclidean distance sqaure */

			for (j=0; j<nfeatures; j++)
			{					
				int addr = point_id + j*npoints;					/* appropriate index of data point */
				float diff = (features[addr] -
							  clusters[cluster_base_index + j]);	/* distance between a data point to cluster centers */
				ans = ans + (diff*diff);									/* sum of squares */
			}

			/* see if distance is smaller than previous ones:
			if so, change minimum distance and save index of cluster center */
			if (ans < FLT_MAX) {
				min_dist = ans;
				cluster_id    = i;
			}
		}

		/* assign the membership to object point_id */
		membership[point_id] = cluster_id;
	}
}

/* ------------------- kmeansCuda() ------------------------ */    
int kmeansCuda(float  **feature,				/* in: [npoints][nfeatures] */
           int      nfeatures,				/* number of attributes for each point */
           int      npoints,				/* number of data points */
           int      nclusters,				/* number of clusters */
           int     *membership,				/* which cluster the point belongs to */
		   float  **clusters,				/* coordinates of cluster centers */
		   int     *new_centers_len,		/* number of elements in each cluster */
           float  **new_centers				/* sum of elements in each cluster */
		   )
{
	int delta = 0;			/* if point has moved */
	int i,j;				/* counters */

	allocateMemory(npoints, nfeatures, nclusters, feature);

	/* copy membership (host to host) */
	for (i = 0; npoints > i; i++)
		membership[i] = -1;

	/* copy clusters (host to host) */
	for (i = 0; nclusters > i; i++)
		for (j = 0; nfeatures > j; j++)
			clusters[i][j] = 0.0;

	kmeansPoint(feature, nfeatures, npoints, nclusters, membership, clusters, block_clusters, block_deltas);

	/* for each point, sum data points in each cluster
	   and see if membership has changed:
	     if so, increase delta and change old membership, and update new_centers;
	     otherwise, update new_centers */
	delta = 0;
	for (i = 0; npoints > i; i++)
	{		
		int cluster_id = membership[i];
		new_centers_len[cluster_id]++;
		if (membership[i] != -1)
		{
			delta++;
		}
		for (j = 0; nfeatures > j; j++)
		{			
			new_centers[cluster_id][j] += feature[i*nfeatures + j];
		}
	}

	deallocateMemory();

	return delta;
}

/* ------------------- kmeans_clustering() ------------------------ */    
float **kmeans_clustering(float **features,
                       int    numAttributes,
                       int    numObjects,
                       int    nclusters,
                       float  threshold,
                       int    *membership)
{
    int    i, j, index;
    int    *new_centers_len;
    float **new_centers;
    float **cluster_centres;

    new_centers_len = (int *) malloc(nclusters * sizeof(int));
    new_centers = (float **) malloc(nclusters * sizeof(float *));
    for (i = 0; i < nclusters; i++)
        new_centers[i] = (float *) malloc(numAttributes * sizeof(float));

    cluster_centres = (float **) malloc(nclusters * sizeof(float *));
    for (i = 0; i < nclusters; i++)
        cluster_centres[i] = (float *) malloc(numAttributes * sizeof(float));

    /* initialize new_centers_len and new_centers */
    for (i = 0; i < nclusters; i++) {
        new_centers_len[i] = 0;
        for (j = 0; j < numAttributes; j++)
            new_centers[i][j] = 0.0;
    }

    /* initialize membership */
    for (i = 0; i < numObjects; i++)
        membership[i] = -1;

    /* initialize cluster_centres */
    for (i = 0; i < nclusters; i++)
        for (j = 0; j < numAttributes; j++)
            cluster_centres[i][j] = features[i][j];

    int loop = 0;
    while (1) {
        loop++;
        int delta = kmeansCuda(features, numAttributes, numObjects, nclusters, membership, cluster_centres, new_centers_len, new_centers);

        /* update cluster_centres */
        for (i = 0; i < nclusters; i++)
            for (j = 0; j < numAttributes; j++)
                cluster_centres[i][j] = new_centers[i][j] / new_centers_len[i];

        if (delta == 0 || loop >= 1000)
            break;
    }

    free(new_centers_len);
    for (i = 0; i < nclusters; i++)
        free(new_centers[i]);
    free(new_centers);

    return cluster_centres;
}

