    KmCai = 3.59e-3;
    KmCao = 1.3;
    KmNai = 12.29;
    KmNao = 87.5;
    ksat = 0.27;
    nu = 0.35;
    Kdact = 0.256e-3;
    Q10NCX = 1.57;
    IbarSLCaP = 0.0673;
