    Bmax_Nasl = 1.65;
    koff_na = 1e-3;
    kon_na = 0.1e-3;
    Bmax_TnClow = 70e-3;
    koff_tncl = 19.6e-3;
    kon_tncl = 32.7;
    Bmax_TnChigh = 140e-3;
    koff_tnchca = 0.032e-3;
    kon_tnchca = 2.37;
    koff_tnchmg = 3.33e-3;
    kon_tnchmg = 3e-3;
    Bmax_myosin = 140e-3;
    koff_myoca = 0.46e-3;
    kon_myoca = 13.8;
    koff_myomg = 0.057e-3;
    kon_myomg = 0.0157;
    Bmax_SR = 19 * 0.9e-3;
    koff_sr = 60e-3;
    kon_sr = 100;
    Bmax_SLlowsl = 37.38e-3 * Vmyo / Vsl;
    Bmax_SLlowj = 4.62e-3 * Vmyo / Vjunc * 0.1;
    koff_sll = 1300e-3;
    kon_sll = 100;
    Bmax_SLhighsl = 13.35e-3 * Vmyo / Vsl;
    Bmax_SLhighj = 1.65e-3 * Vmyo / Vjunc * 0.1;
    koff_slh = 30e-3;
    kon_slh = 100;
    Bmax_Csqn = 2.7;
    koff_csqn = 65;
    kon_csqn = 100;

    // I_Na: Fast Na Current
    am = 0.32 * (d_initvalu_39 + 47.13) / (1 - exp(-0.1 * (d_initvalu_39 + 47.13)));
    bm = 0.08 * exp(-d_initvalu_39 / 11);
    if (d_initvalu_39 >= -40) {
        ah = 0;
        aj = 0;
        bh = 1 / (0.13 * (1 + exp(-(d_initvalu_39 + 10.66) / 11.1)));
