    I_pca_junc = Fjunc * pow(Q10SLCaP, Qpow) * IbarSLCaP * pow(d_initvalu_36, 1.6) / (pow(KmPCa, 1.6) + pow(d_initvalu_36, 1.6));
    I_pca_sl = Fsl * pow(Q10SLCaP, Qpow) * IbarSLCaP * pow(d_initvalu_37, 1.6) / (pow(KmPCa, 1.6) + pow(d_initvalu_37, 1.6));
    I_pca = I_pca_junc + I_pca_sl;
    d_initvalu_44 = -I_pca * Cmem / (Vmyo * 2 * FoRT) * 1e3;

    // I_cabk: Ca Background Current
    I_cabk_junc = Fjunc * GCaB * (d_initvalu_39 - eca_junc);
    I_cabk_sl = Fsl * GCaB * (d_initvalu_39 - eca_sl);
    I_cabk = I_cabk_junc + I_cabk_sl;
    d_initvalu_46 = -I_cabk * Cmem / (Vmyo * 2 * FoRT) * 1e3;

    // SR fluxes: Calcium Release, SR Ca pump, SR Ca leak
    MaxSR = 15;
    MinSR = 1;
    kCaSR = MaxSR - (MaxSR - MinSR) / (1 + pow(ec50SR / d_initvalu_31, 2.5));
    koSRCa = koCa / kCaSR;
    kiSRCa = kiCa * kCaSR;
    RI = 1 - d_initvalu_14 - d_initvalu_15 - d_initvalu_16;
    d_initvalu_14 = (kim * RI - kiSRCa * d_initvalu_36 * d_initvalu_14) - (koSRCa * pow(d_initvalu_36, 2) * d_initvalu_14 - kom * d_initvalu_15);
    d_initvalu_15 = (koSRCa * pow(d_initvalu_36, 2) * d_initvalu_14 - kom * d_initvalu_15) - (kiSRCa * d_initvalu_36 * d_initvalu_15 - kim * d_initvalu_16);
    d_initvalu_16 = (kiSRCa * d_initvalu_36 * d_initvalu_15 - kim * d_initvalu_16) - (kom * d_initvalu_16 - koSRCa * pow(d_initvalu_36, 2) * RI);
    J_SRCarel = ks * d_initvalu_15 * (d_initvalu_31 - d_initvalu_36);
    J_serca = pow(Q10SRCaP, Qpow) * Vmax_SRCaP * (pow((d_initvalu_38 / Kmf), hillSRCaP) - pow((d_initvalu_31 / Kmr), hillSRCaP)) / (1 + pow((d_initvalu_38 / Kmf), hillSRCaP) + pow((d_initvalu_31 / Kmr), hillSRCaP));
    J_SRleak = 5.348e-6 * (d_initvalu_31 - d_initvalu_36);

    // Cytosolic Ca Buffers
    d_initvalu_17 = kon_na * d_initvalu_32 * (Bmax_Naj - d_initvalu_17) - koff_na * d_initvalu_17;
    d_initvalu_18 = kon_na * d_initvalu_33 * (Bmax_Nasl - d_initvalu_18) - koff_na * d_initvalu_18;

    // Junctional and SL Ca Buffers
    d_initvalu_26 = kon_sll * d_initvalu_36 * (Bmax_SLlowj - d_initvalu_26) - koff_sll * d_initvalu_26;
    d_initvalu_27 = kon_sll * d_initvalu_37 * (Bmax_SLlowsl - d_initvalu_27) - koff_sll * d_initvalu_27;
    d_initvalu_28 = kon_slh * d_initvalu_36 * (Bmax_SLhighj - d_initvalu_28) - koff_slh * d_initvalu_28;
    d_initvalu_29 = kon_slh * d_initvalu_37 * (Bmax_SLhighsl - d_initvalu_29) - koff_slh * d_initvalu_29;

    // SR Ca Concentrations
    d_initvalu_30 = kon_csqn * d_initvalu_31 * (Bmax_Csqn - d_initvalu_30) - koff_csqn * d_initvalu_30;
    oneovervsr = 1 / Vsr;
    d_initvalu_31 = J_serca * Vmyo * oneovervsr - (J_SRleak * Vmyo * oneovervsr + J_SRCarel) - d_initvalu_30;

    // Sodium Concentrations
    I_Na_tot_junc = I_Na_junc + I_nabk_junc + 3 * I_ncx_junc + 3 * I_nak_junc + I_CaNa_junc;
    I_Na_tot_sl = I_Na_sl + I_nabk_sl + 3 * I_ncx_sl + 3 * I_nak_sl + I_CaNa_sl;
    d_initvalu_32 = -I_Na_tot_junc * Cmem / (Vjunc * FoRT) + J_na_juncsl / Vjunc * (d_initvalu_33 - d_initvalu_32) - d_initvalu_17;
    d_initvalu_33 = -I_Na_tot_sl * Cmem * oneovervsl / FoRT + J_na_juncsl * oneovervsl * (d_initvalu_32 - d_initvalu_33) + J_na_slmyo * oneovervsl * (d_initvalu_34 - d_initvalu_33) - d_initvalu_18;
    d_initvalu_34 = J_na_slmyo / Vmyo * (d_initvalu_33 - d_initvalu_34);

    // Potassium Concentration
    I_K_tot = I_to + I_kr + I_ks + I_ki - 2 * I_nak + I_CaK + I_kp;
    d_initvalu_35 = 0;

    // Calcium Concentrations
    I_Ca_tot_junc = I_Ca_junc + I_cabk_junc + I_pca_junc - 2 * I_ncx_junc;
    I_Ca_tot_sl = I_Ca_sl + I_cabk_sl + I_pca_sl - 2 * I_ncx_sl;
    d_initvalu_36 = -I_Ca_tot_junc * Cmem / (Vjunc * 2 * FoRT) + J_ca_juncsl / Vjunc * (d_initvalu_37 - d_initvalu_36) + J_ca_slmyo / Vjunc * (d_initvalu_38 - d_initvalu_36) + J_SRCarel * Vsr / Vjunc;
    d_initvalu_37 = -I_Ca_tot_sl * Cmem * oneovervsl / (2 * FoRT) + J_ca_juncsl * oneovervsl * (d_initvalu_36 - d_initvalu_37) + J_ca_slmyo * oneovervsl * (d_initvalu_38 - d_initvalu_37) - J_CaB_sl;
    d_initvalu_38 = -J_serca - J_CaB_cytosol + J_ca_slmyo / Vmyo * (d_initvalu_37 - d_initvalu_38);

    // Simulation type
    state = 1;
    I_app = 0;
    if (state == 1) {
        if (fmod(timeinst, cycleLength) <= 5) {
            I_app = 9.5;
        } else {
            I_app = 0.0;
