void euclid(LatLong *locations, float *distances, int numRecords,float lat, float lng)
{
    #pragma omp parallel for
    for (int i = 0; i < numRecords; i++) {
        float *dist = distances + i;
        LatLong *latLong = locations + i;
        *dist = (float)sqrt((lat - latLong->lat) * (lat - latLong->lat) + (lng - latLong->lng) * (lng - latLong->lng));
    }
}

int main(int argc, char* argv[])
{
    int    i = 0;
    float lat, lng;
    int quiet = 0, timing = 0, platform = 0, device = 0;

    Record records[MAX_RECORDS];
    LatLong locations[MAX_RECORDS];
    char filename[100];
    int resultsCount = 10;
    int numRecords = 0;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    numRecords = loadData(filename, records, locations, &numRecords);
    if (numRecords < resultsCount) resultsCount = numRecords;

    float *distances = (float *)malloc(sizeof(float) * numRecords);

    euclid(locations, distances, numRecords, lat, lng);

    findLowest(records, distances, numRecords, resultsCount);

    if (!quiet)
        for (i = 0; resultsCount > i; i++) {
            printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
        }
    free(distances);

    return 0;
}

