int maximum(int a, int b, int c) {
  int k;
  if (a <= b)
    k = b;
  else
    k = a;

  if (k <= c)
    return c;
  else
    return k;
}

void needle_openmp_1(int* referrence, int* matrix, int max_cols, int penalty, int i, int block_width) {
  int index = max_cols * 16 * (i - 1) + 16 * 0;
  int index_n = max_cols * 16 * (i - 1) + 1;
  int index_w = max_cols * 16 * (i - 1) + max_cols;
  int index_nw = max_cols * 16 * (i - 1);

  int temp[17][17];
  int ref[16][16];

  for (int ty = 0; ty < 16; ty++)
    ref[ty][0] = referrence[index + max_cols * ty];

  temp[0][0] = matrix[index_nw];

  for (int tx = 1; tx <= 16; tx++) {
    temp[tx][0] = matrix[index_w + max_cols * tx];
  }

  for (int tx = 1; tx <= 16; tx++) {
    temp[0][tx] = matrix[index_n];
  }

  for (int m = 0; m < 16; m++) {
    for (int tx = 0; tx <= m; tx++) {
      int t_index_x = tx + 1;
      int t_index_y = m - tx + 1;

      temp[t_index_y][t_index_x] = maximum(temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                                           temp[t_index_y][t_index_x - 1] - penalty,
                                           temp[t_index_y - 1][t_index_x] - penalty);
    }
  }

  for (int m = 15; m >= 0; m--) {
    for (int tx = 0; tx <= m; tx++) {
      int t_index_x = tx + 16 - m;
      int t_index_y = 16 - tx;

      temp[t_index_y][t_index_x] = maximum(temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
