void needle_openmp_1(int* referrence, int* matrix, int cols, int penalty, int i, int block_width) {
  int index = cols * BLOCK_SIZE * (i - 1) + BLOCK_SIZE * 0;
  int index_n = cols * BLOCK_SIZE * (i - 1) + 1;
  int index_w = cols * BLOCK_SIZE * (i - 1) + cols;
  int index_nw = cols * BLOCK_SIZE * (i - 1);

  int temp[BLOCK_SIZE + 1][BLOCK_SIZE + 1];
  int ref[BLOCK_SIZE][BLOCK_SIZE];

  for (int ty = 0; ty < BLOCK_SIZE; ty++)
    for (int tx = 0; tx < BLOCK_SIZE; tx++)
      ref[ty][tx] = referrence[index + cols * ty + tx];

  temp[0][0] = matrix[index_nw];

  for (int tx = 0; tx < BLOCK_SIZE; tx++)
    temp[tx + 1][0] = matrix[index_w + cols * tx];

  for (int tx = 0; tx < BLOCK_SIZE; tx++)
    temp[0][tx + 1] = matrix[index_n];

  for (int m = 0; m < BLOCK_SIZE; m++) {
    for (int tx = 0; tx <= m; tx++) {
      int t_index_x = tx + 1;
      int t_index_y = m - tx + 1;

      temp[t_index_y][t_index_x] = maximum(temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                                            temp[t_index_y][t_index_x - 1] - penalty,
                                            temp[t_index_y - 1][t_index_x] - penalty);
    }
  }

  for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
    for (int tx = 0; tx <= m; tx++) {
      int t_index_x = tx + BLOCK_SIZE - m;
      int t_index_y = BLOCK_SIZE - tx;

      temp[t_index_y][t_index_x] = maximum(temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                                            temp[t_index_y][t_index_x - 1] - penalty,
                                            temp[t_index_y - 1][t_index_x] - penalty);
    }
  }

  for (int ty = 0; ty < BLOCK_SIZE; ty++)
    for (int tx = 0; tx < BLOCK_SIZE; tx++)
      matrix[index + ty * cols + tx] = temp[ty + 1][tx + 1];
}

void needle_openmp_2(int* referrence, int* matrix, int cols, int penalty, int i, int block_width) {
  int index = cols * BLOCK_SIZE * (block_width - i) + BLOCK_SIZE * (block_width - i);
  int index_n = cols * BLOCK_SIZE * (block_width - i) + 1;
  int index_w = cols * BLOCK_SIZE * (block_width - i) + cols;
  int index_nw = cols * BLOCK_SIZE * (block_width - i);

  int temp[BLOCK_SIZE + 1][BLOCK_SIZE + 1];
  int ref[BLOCK_SIZE][BLOCK_SIZE];

  for (int ty = 0; ty < BLOCK_SIZE; ty++)
    for (int tx = 0; tx < BLOCK_SIZE; tx++)
      ref[ty][tx] = referrence[index + cols * ty + tx];

  temp[0][0] = matrix[index_nw];

  for (int tx = 0; tx < BLOCK_SIZE; tx++)
    temp[tx + 1][0] = matrix[index_w + cols * tx];

  for (int tx = 0; tx < BLOCK_SIZE; tx++)
    temp[0][tx + 1] = matrix[index_n];

  for (int m = 0; m < BLOCK_SIZE; m++) {
    for (int tx = 0; tx <= m; tx++) {
